import React, { useState, useRef } from 'react';
import { ThreadsAccount, UserProfile, DNALabAnalysis, UserRole, BrandSettings } from '../../types';
import { fetchUserThreads } from '../../services/threadsService';
import { fetchRecentPostCaptions } from '../../services/facebookService';
import { generateDNALabAnalysis } from '../../services/gemini/text';
import { generateImage } from '../../services/gemini/media';
import { checkAndUseQuota } from '../../services/authService';
import { buildDNALabImagePrompt } from '../../services/promptTemplates';

interface Props {
    accounts?: ThreadsAccount[]; // Optional now, as it might be used in Analytics where accounts need to be passed
    settings: BrandSettings;
    user: UserProfile | null;
    onQuotaUpdate: () => void;
}

const DigitalDNALab: React.FC<Props> = ({ accounts = [], settings, user, onQuotaUpdate }) => {
    // If accounts not passed from parent, use settings (fallback)
    const threadAccounts = accounts.length > 0 ? accounts : (settings.threadsAccounts || []);

    const [selectedThreadId, setSelectedThreadId] = useState(threadAccounts[0]?.id || '');
    const [useFb, setUseFb] = useState(true);
    const [useThreads, setUseThreads] = useState(true);

    const [isAnalyzing, setIsAnalyzing] = useState(false);
    const [result, setResult] = useState<DNALabAnalysis | null>(null);
    const [loadingStage, setLoadingStage] = useState('');
    const cardRef = useRef<HTMLDivElement>(null);

    const role = user?.role || 'user';

    const getRoleLabel = (role: UserRole) => {
        switch(role) {
            case 'starter': return 'Starter (職業裝)';
            case 'pro': return 'Pro (稀有配件)';
            case 'business': return 'Business (VIP光環)';
            case 'admin': return 'GM (神裝)';
            default: return 'Free (初始型態)';
        }
    };

    const handleAnalyze = async () => {
        if (!user) return alert("請先登入");

        // Validation
        const hasFbConfig = settings.facebookPageId && settings.facebookToken;
        const hasThreadsConfig = threadAccounts.length > 0;

        if (useFb && !hasFbConfig) return alert("無法分析 FB：請先至設定頁面連結 Facebook 粉絲專頁。");
        if (useThreads && !hasThreadsConfig) return alert("無法分析 Threads：請先連結 Threads 帳號。");
        if (!useFb && !useThreads) return alert("請至少選擇一種數據來源！");

        // [BILLING] DNA Lab: 10 Points
        const COST = 10;
        const allowed = await checkAndUseQuota(user.user_id, COST, 'DNA_LAB_ANALYSIS');
        if (!allowed) return;
        onQuotaUpdate();

        setIsAnalyzing(true);
        setResult(null);

        try {
            let combinedText = "";

            // 1. Fetch Facebook Data
            if (useFb && hasFbConfig) {
                setLoadingStage('正在掃描 Facebook 粉專 (Public Persona)...');
                try {
                    const fbPosts = await fetchRecentPostCaptions(settings.facebookPageId, settings.facebookToken, 10);
                    if (fbPosts.length > 0) {
                        combinedText += `\n\n=== [SOURCE: FACEBOOK PAGE (Public/Professional Layer)] ===\n${fbPosts.join('\n---\n')}`;
                    }
                } catch (e) {
                    console.warn("FB Fetch Failed", e);
                }
            }

            // 2. Fetch Threads Data
            if (useThreads && hasThreadsConfig) {
                setLoadingStage('正在掃描 Threads 帳號 (Inner/Chaos Persona)...');
                const targetAccount = selectedThreadId ? threadAccounts.find(a => a.id === selectedThreadId) : threadAccounts[0];
                if (targetAccount) {
                    try {
                        const posts = await fetchUserThreads(targetAccount, 15);
                        const postTexts = posts.map((p: any) => p.text).filter(Boolean);
                        if (postTexts.length > 0) {
                            combinedText += `\n\n=== [SOURCE: THREADS (Private/Authentic Layer)] ===\n${postTexts.join('\n---\n')}`;
                        }
                    } catch (e) {
                        console.warn("Threads Fetch Failed", e);
                    }
                }
            }

            if (combinedText.length < 50) throw new Error("抓取到的貼文內容過少，無法進行基因分析。");

            // 3. Analyze DNA (Gemini)
            setLoadingStage('AI 正在融合雙重人格數據...');
            const analysis = await generateDNALabAnalysis([combinedText]); // API expects array but we formatted it as one block

            // 4. Generate Visual (RPG Style)
            setLoadingStage(`正在生成 RPG 寵物 (${getRoleLabel(role)})...`);

            const prompt = buildDNALabImagePrompt(analysis.visualDescription, role);
            const imageUrl = await generateImage(prompt, role); 

            setResult({ ...analysis, imageUrl });

        } catch (e: any) {
            alert(`分析失敗: ${e.message}`);
        } finally {
            setIsAnalyzing(false);
            setLoadingStage('');
        }
    };

    return (
        <div className="max-w-5xl mx-auto p-4 md:p-8 space-y-8 animate-fade-in pb-20">
            {/* Header */}
            <div className="text-center space-y-2">
                <h2 className="text-3xl md:text-5xl font-black text-white tracking-tighter drop-shadow-[0_0_15px_rgba(0,242,234,0.5)]">
                    🧬 數位基因實驗室
                </h2>
                <p className="text-gray-400 font-medium tracking-widest text-xs md:text-sm uppercase">
                    Cross-Platform Persona Synthesis
                </p>
                <div className="inline-block bg-gray-800 border border-gray-600 px-4 py-1 rounded-full text-xs text-gray-300 mt-2">
                    目前會員等級：<span className="text-primary font-bold">{getRoleLabel(role)}</span>
                </div>
            </div>

            {/* Source Selection Controls */}
            <div className="bg-card p-6 rounded-2xl border border-gray-700 flex flex-col items-center gap-6">

                <div className="flex flex-wrap gap-4 justify-center">
                    {/* FB Toggle */}
                    <label className={`flex items-center gap-3 p-3 rounded-xl border cursor-pointer transition-all ${useFb ? 'bg-blue-900/30 border-blue-500' : 'bg-dark border-gray-700 opacity-50'}`}>
                        <input type="checkbox" checked={useFb} onChange={e => setUseFb(e.target.checked)} className="w-5 h-5 accent-blue-500" />
                        <div>
                            <div className="text-white font-bold text-sm">Facebook 粉專</div>
                            <div className="text-[10px] text-gray-400">來源: {settings.facebookPageId ? '已連結' : '未設定'}</div>
                        </div>
                    </label>

                    <div className="text-2xl text-gray-600 self-center">+</div>

                    {/* Threads Toggle */}
                    <label className={`flex items-center gap-3 p-3 rounded-xl border cursor-pointer transition-all ${useThreads ? 'bg-pink-900/30 border-pink-500' : 'bg-dark border-gray-700 opacity-50'}`}>
                        <input type="checkbox" checked={useThreads} onChange={e => setUseThreads(e.target.checked)} className="w-5 h-5 accent-pink-500" />
                        <div>
                            <div className="text-white font-bold text-sm">Threads 帳號</div>
                            {threadAccounts.length > 0 ? (
                                <select 
                                    value={selectedThreadId} 
                                    onClick={e => e.stopPropagation()} // Prevent toggle
                                    onChange={e => setSelectedThreadId(e.target.value)}
                                    className="bg-black/50 border border-gray-600 rounded px-2 py-1 text-[10px] text-white mt-1 outline-none"
                                >
                                    {threadAccounts.map(acc => <option key={acc.id} value={acc.id}>{acc.username}</option>)}
                                </select>
                            ) : <div className="text-[10px] text-red-400">未連結</div>}
                        </div>
                    </label>
                </div>

                <button 
                    onClick={handleAnalyze} 
                    disabled={isAnalyzing}
                    className="bg-gradient-to-r from-blue-600 via-purple-600 to-pink-600 hover:brightness-110 text-white px-8 py-3 rounded-xl font-bold shadow-lg transition-all w-full md:w-auto disabled:opacity-50 disabled:cursor-not-allowed flex items-center justify-center gap-2"
                >
                    {isAnalyzing ? (
                        <><div className="loader w-4 h-4 border-t-white"></div> {loadingStage}</>
                    ) : (
                        '🧪 開始全域融合分析 (10 點)'
                    )}
                </button>
            </div>

            {/* Result Area */}
            {result && (
                <div className="relative w-full max-w-md mx-auto" ref={cardRef}>
                    {/* The Card Container */}
                    <div className="bg-gradient-to-b from-gray-900 to-black rounded-[2rem] border-4 border-purple-500/50 shadow-[0_0_50px_rgba(168,85,247,0.3)] overflow-hidden relative">

                        {/* Decorative Header */}
                        <div className="bg-purple-900/30 p-4 border-b border-purple-500/30 flex justify-between items-center">
                            <span className="text-[10px] font-black tracking-[0.2em] text-purple-300 uppercase">AutoSocial Lab</span>
                            <div className="flex gap-1">
                                <div className="w-2 h-2 rounded-full bg-red-500"></div>
                                <div className="w-2 h-2 rounded-full bg-yellow-500"></div>
                                <div className="w-2 h-2 rounded-full bg-green-500"></div>
                            </div>
                        </div>

                        {/* Character Image */}
                        <div className="aspect-square w-full bg-white relative p-8 flex items-center justify-center overflow-hidden group">
                            {/* Background Pattern */}
                            <div className="absolute inset-0 opacity-10 bg-[url('https://www.transparenttextures.com/patterns/cubes.png')]"></div>

                            {result.imageUrl ? (
                                <img src={result.imageUrl} alt="Character" className="relative z-10 w-full h-full object-contain drop-shadow-2xl filter group-hover:scale-105 transition-transform duration-500" />
                            ) : (
                                <div className="text-black/50 font-bold">Image Gen Failed</div>
                            )}

                            {/* VIP Effect for Business Users */}
                            {role === 'business' && (
                                <div className="absolute top-4 right-4 bg-yellow-400 text-black font-black px-3 py-1 rounded-full text-xs shadow-lg animate-bounce z-20">
                                    👑 VIP USER
                                </div>
                            )}
                        </div>

                        {/* Stats Panel */}
                        <div className="p-6 space-y-6">

                            {/* Title & Name */}
                            <div className="text-center">
                                <h3 className="text-sm font-bold text-gray-400 uppercase tracking-wider mb-1">{result.species}</h3>
                                <h2 className="text-2xl font-black text-white leading-tight bg-clip-text text-transparent bg-gradient-to-r from-purple-400 to-pink-400">
                                    {result.title}
                                </h2>
                            </div>

                            {/* Stats Grid (RPG Style - Updated for Duality) */}
                            <div className="grid grid-cols-2 gap-3 text-xs">
                                <StatBar label="混沌 (Chaos)" value={result.stats.chaos} color="bg-red-500" />
                                <StatBar label="專業 (Professional)" value={result.stats.professionalism || result.stats.chill} color="bg-blue-500" />
                                <StatBar label="知識 (INT)" value={result.stats.intellect} color="bg-green-500" />
                                <StatBar label="攻擊 (ATK)" value={result.stats.aggression} color="bg-orange-500" />
                                <StatBar label="感性 (EMO)" value={result.stats.emo} color="bg-purple-500" />
                                <StatBar label="反差萌 (Duality)" value={result.stats.duality || result.stats.luck} color="bg-yellow-500" />
                            </div>

                            {/* The Roast Comment */}
                            <div className="bg-white/5 p-4 rounded-xl border border-white/10 relative">
                                <span className="absolute -top-2 left-4 text-2xl">❝</span>
                                <p className="text-gray-300 text-sm italic text-center font-medium leading-relaxed pt-2">
                                    {result.comment}
                                </p>
                                <span className="absolute -bottom-4 right-4 text-2xl text-gray-600">❞</span>
                            </div>

                            {/* Footer */}
                            <div className="text-center pt-2">
                                <p className="text-[10px] text-gray-600 font-bold uppercase tracking-widest">
                                    Powered by AutoSocial AI
                                </p>
                            </div>
                        </div>
                    </div>

                    <button onClick={handleDownload} className="mt-6 w-full text-center text-gray-400 hover:text-white text-sm underline">
                        ⭳ 保存截圖
                    </button>
                </div>
            )}
        </div>
    );
};

const StatBar = ({ label, value, color }: { label: string, value: number, color: string }) => (
    <div className="flex flex-col gap-1">
        <div className="flex justify-between text-[10px] font-bold text-gray-400">
            <span>{label}</span>
            <span>{value || 0}</span>
        </div>
        <div className="w-full h-2 bg-gray-800 rounded-full overflow-hidden">
            <div className={`h-full ${color}`} style={{ width: `${value || 0}%` }}></div>
        </div>
    </div>
);

export default DigitalDNALab;

import React, { useState, useEffect } from 'react';
import { BrandSettings, AnalyticsData, TopPostData } from '../types';
import { fetchPageAnalytics, fetchPageTopPosts } from '../services/facebookService';
import { generateWeeklyReport } from '../services/geminiService';
import { generatePostDraft } from '../services/geminiService'; 
import { checkAndUseQuota } from '../services/authService';
import { getCurrentUser } from '../services/authService';
// Import DNALab from the threads directory (now universal)
import DigitalDNALab from './threads/DigitalDNALab';
import { getUserProfile } from '../services/features/user';

interface Props {
  settings: BrandSettings;
}

const AnalyticsDashboard: React.FC<Props> = ({ settings }) => {
  const [activeTab, setActiveTab] = useState<'overview' | 'dna_lab'>('overview');
  const [analytics, setAnalytics] = useState<AnalyticsData | null>(null);
  const [topPosts, setTopPosts] = useState<{ topReach?: TopPostData, topEngagement?: TopPostData } | null>(null);

  const [loadingStats, setLoadingStats] = useState(false);
  const [errorMsg, setErrorMsg] = useState('');

  // Need full user profile for DNA Lab quota/role
  const [fullUser, setFullUser] = useState<any>(null);

  useEffect(() => {
    const u = getCurrentUser();
    if (u) {
        getUserProfile(u.uid).then(setFullUser);
    }

    if (settings.facebookPageId && settings.facebookToken) {
        loadData();
    }
  }, [settings.facebookPageId, settings.facebookToken]);

  const loadData = async () => {
    setLoadingStats(true);
    try {
      const data = await fetchPageAnalytics(settings.facebookPageId, settings.facebookToken);
      setAnalytics(data);
      const top = await fetchPageTopPosts(settings.facebookPageId, settings.facebookToken);
      setTopPosts(top);
    } catch (e: any) {
      setErrorMsg(e.message);
    } finally {
      setLoadingStats(false);
    }
  };

  const handleDownloadCSV = () => {
      if (!analytics) return;
      const headers = "Followers,Reach(28d),EngagementRate,Date\n";
      const row = `${analytics.followers},${analytics.reach},${analytics.engagementRate}%,${new Date().toLocaleDateString()}\n`;
      const blob = new Blob([headers + row], { type: 'text/csv;charset=utf-8;' });
      const url = URL.createObjectURL(blob);
      const link = document.createElement('a');
      link.href = url;
      link.download = `report_${settings.facebookPageId}_${new Date().toISOString().slice(0,10)}.csv`;
      link.click();
  };

  if (!settings.facebookPageId && activeTab === 'overview') return <div className="p-10 text-center text-white">請先在設定頁面連結 Facebook 粉專 API</div>;

  return (
    <div className="max-w-6xl mx-auto space-y-8 animate-fade-in pb-10">

      <div className="flex flex-col md:flex-row justify-between items-center gap-4">
          <h2 className="text-2xl font-bold text-white">數據分析中心</h2>
          <div className="flex gap-2">
              <button onClick={() => setActiveTab('overview')} className={`px-4 py-2 rounded font-bold transition-colors ${activeTab==='overview'?'bg-primary text-black':'bg-dark text-gray-400 hover:text-white'}`}>📊 營運數據</button>
              <button onClick={() => setActiveTab('dna_lab')} className={`px-4 py-2 rounded font-bold transition-colors ${activeTab==='dna_lab'?'bg-purple-500 text-white':'bg-dark text-gray-400 hover:text-white'}`}>🧬 數位寵物 (DNA Lab)</button>
          </div>
      </div>

      {activeTab === 'overview' && analytics && (
          <section className="space-y-6">
            <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
               <div className="bg-card p-6 rounded-xl border border-gray-700">
                 <p className="text-gray-400 text-sm">總粉絲數</p>
                 <p className="text-3xl font-bold text-white mt-2">{analytics.followers.toLocaleString()}</p>
               </div>
               <div className="bg-card p-6 rounded-xl border border-gray-700">
                 <p className="text-gray-400 text-sm">貼文觸及 (28天)</p>
                 <p className="text-3xl font-bold text-white mt-2">{analytics.reach.toLocaleString()}</p>
               </div>
               <div className="bg-card p-6 rounded-xl border border-gray-700">
                 <p className="text-gray-400 text-sm">互動率</p>
                 <p className="text-3xl font-bold text-blue-400 mt-2">{analytics.engagementRate}%</p>
               </div>
               <div className="flex flex-col gap-2">
                  <button onClick={handleDownloadCSV} className="bg-green-700 text-white py-3 rounded font-bold hover:bg-green-600">📥 下載 CSV</button>
               </div>
            </div>
          </section>
      )}

      {activeTab === 'dna_lab' && (
          <DigitalDNALab 
              settings={settings} 
              user={fullUser} 
              accounts={settings.threadsAccounts} // Explicitly pass accounts
              onQuotaUpdate={() => { if(fullUser) getUserProfile(fullUser.user_id).then(setFullUser); }} 
          />
      )}
    </div>
  );
};

export default AnalyticsDashboard;

import React, { useState, useEffect } from 'react';
import { BrandSettings, ThreadsAccount, UserProfile } from '../types';
import AccountManager from './threads/AccountManager';
import InteractionManager from './threads/InteractionManager';
import ContentGenerator from './threads/ContentGenerator';
import DigitalDNALab from './threads/DigitalDNALab';

interface Props {
  settings: BrandSettings;
  user: UserProfile | null;
  onSaveSettings: (settings: BrandSettings) => void;
  onQuotaUpdate: () => void;
}

const ThreadsNurturePanel: React.FC<Props> = ({ settings, user, onSaveSettings, onQuotaUpdate }) => {
  const [activeTab, setActiveTab] = useState<'accounts' | 'interaction' | 'generator' | 'dna_lab'>('accounts');
  const [accounts, setAccounts] = useState<ThreadsAccount[]>(settings.threadsAccounts || []);

  // Sync state when external settings change (e.g. from OAuth callback in App.tsx)
  useEffect(() => {
      if (JSON.stringify(settings.threadsAccounts) !== JSON.stringify(accounts)) {
          setAccounts(settings.threadsAccounts || []);
      }
  }, [settings.threadsAccounts]);

  // Update parent settings whenever local accounts change
  const handleAccountsChange = (newAccounts: ThreadsAccount[]) => {
      setAccounts(newAccounts);
      onSaveSettings({ ...settings, threadsAccounts: newAccounts });
  };

  return (
    <div className="max-w-6xl mx-auto p-4 animate-fade-in pb-20">
      <div className="flex justify-between items-center mb-6">
          <h2 className="text-3xl font-bold text-white">Threads 養號農場</h2>
          <div className="text-xs text-gray-400">多帳號管理 • 風格學習 • 批量生成</div>
      </div>

      <div className="flex border-b border-gray-700 mb-6 overflow-x-auto custom-scrollbar">
        <button onClick={() => setActiveTab('accounts')} className={`px-6 py-3 font-bold whitespace-nowrap transition-colors ${activeTab === 'accounts' ? 'text-white border-b-2' : 'text-gray-500 hover:text-gray-300'}`}>帳號管理</button>
        <button onClick={() => setActiveTab('interaction')} className={`px-6 py-3 font-bold whitespace-nowrap transition-colors ${activeTab === 'interaction' ? 'text-pink-400 border-b-2 border-pink-400' : 'text-gray-500 hover:text-gray-300'}`}>留言互動</button>
        <button onClick={() => setActiveTab('generator')} className={`px-6 py-3 font-bold whitespace-nowrap transition-colors ${activeTab === 'generator' ? 'text-white border-b-2' : 'text-gray-500 hover:text-gray-300'}`}>內容生成</button>
        <button onClick={() => setActiveTab('dna_lab')} className={`px-6 py-3 font-bold whitespace-nowrap transition-colors ${activeTab === 'dna_lab' ? 'text-purple-400 border-b-2 border-purple-400' : 'text-gray-500 hover:text-gray-300'}`}>🧪 基因實驗室</button>
      </div>

      {activeTab === 'accounts' && (
          <AccountManager 
              accounts={accounts} 
              setAccounts={handleAccountsChange}
              settings={settings}
              onSaveSettings={onSaveSettings}
              user={user} 
              onQuotaUpdate={onQuotaUpdate} 
          />
      )}

      {activeTab === 'interaction' && (
          <InteractionManager 
              accounts={accounts} 
              user={user} 
              onQuotaUpdate={onQuotaUpdate} 
          />
      )}

      {activeTab === 'generator' && (
          <ContentGenerator 
              settings={settings} 
              accounts={accounts} 
              user={user} 
              onQuotaUpdate={onQuotaUpdate} 
          />
      )}

      {activeTab === 'dna_lab' && (
          <DigitalDNALab 
              settings={settings}
              user={user}
              accounts={accounts} // Ensure explicit pass
              onQuotaUpdate={onQuotaUpdate}
          />
      )}
    </div>
  );
};

export default ThreadsNurturePanel;

export interface ApiResponse<T = any> {
  success: boolean;
  data?: T;
  error?: {
    code: ErrorCode;
    message: string;
    details?: any;
  };
  timestamp: number;
}

export enum ErrorCode {
  UNAUTHORIZED = 'AUTH_001',
  FORBIDDEN = 'AUTH_002',
  TOKEN_EXPIRED = 'AUTH_003',
  NOT_FOUND = 'RES_001',
  VALIDATION_ERROR = 'RES_002',
  QUOTA_EXCEEDED = 'BIZ_001',
  FEATURE_LOCKED = 'BIZ_002',
  FACEBOOK_API_ERROR = 'EXT_FB_001',
  AI_API_ERROR = 'EXT_AI_001',
  INTERNAL_ERROR = 'SYS_001',
  MAINTENANCE_MODE = 'SYS_002',
  RATE_LIMIT_EXCEEDED = 'SYS_003'
}

export type UserRole = 'user' | 'starter' | 'pro' | 'business' | 'admin';

// NEW: Queue System Types
export interface QueueItem {
  id: string;
  userId: string;
  action: string;
  createdAt: number;
  expiresAt: number; // TTL to prevent zombies
  status: 'waiting' | 'processing';
}

export interface QueueState {
  isQueuing: boolean;
  position: number;
  totalWaiting: number;
  currentAction: string;
}

// NEW: Subscription Info
export type SubscriptionStatus = 'active' | 'canceled' | 'past_due' | 'none';
export type PaymentProvider = 'ecpay' | 'bank_api' | 'manual';

export interface UserSubscription {
  status: SubscriptionStatus;
  planId: 'starter' | 'pro' | 'business';
  provider: PaymentProvider;
  subscriptionId: string; // ID on the payment gateway
  nextBillingDate: number;
  lastPaymentDate: number;
  cancelAtPeriodEnd: boolean;
}

// NEW: Batch Tracking
export interface QuotaBatch {
  id: string;
  amount: number;        // Current remaining balance in this batch
  initialAmount: number; // Original amount (for records)
  expiresAt: number;     // Expiration Timestamp
  source: 'subscription' | 'topup' | 'referral' | 'admin_gift' | 'trial';
  addedAt: number;
}

export interface UserProfile {
  user_id: string;
  email: string;
  role: UserRole;
  quota_total: number; // Sum of all valid batches (Read-only view)
  quota_used: number;  // Lifetime usage stats
  quota_reset_date: number; // Deprecated but kept for legacy UI compatibility (represents earliest expiry)
  quota_batches?: QuotaBatch[]; // NEW: The source of truth
  subscription?: UserSubscription; // NEW: Subscription tracking
  expiry_warning_level?: 0 | 1 | 2; 
  isSuspended: boolean;
  unlockedFeatures: string[]; 
  referralCode?: string;
  referredBy?: string;
  referralCount?: number;
  last_api_call_timestamp?: number; 
  created_at: number;
  updated_at: number;
}

export interface QuotaTransaction {
  txId: string;
  userId: string;
  amount: number; // Negative for cost, Positive for refill
  balanceAfter: number;
  action: string;
  refId?: string; // Optional: Post ID or Task ID
  timestamp: number;
  metadata?: any;
}

