import React, { useState, useRef } from 'react';
import { ThreadsAccount, UserProfile, DNALabAnalysis, UserRole, BrandSettings } from '../../types';
import { fetchUserThreads } from '../../services/threadsService';
import { fetchRecentPostCaptions } from '../../services/facebookService';
import { generateDNALabAnalysis } from '../../services/gemini/text';
import { generateImage } from '../../services/gemini/media';
import { checkAndUseQuota } from '../../services/authService';
import { buildDNALabImagePrompt } from '../../services/promptTemplates';

interface Props {
    accounts?: ThreadsAccount[]; // Optional now, as it might be used in Analytics where accounts need to be passed
    settings: BrandSettings;
    user: UserProfile | null;
    onQuotaUpdate: () => void;
}

const DigitalDNALab: React.FC<Props> = ({ accounts = [], settings, user, onQuotaUpdate }) => {
    // If accounts not passed from parent, use settings (fallback)
    const threadAccounts = accounts.length > 0 ? accounts : (settings.threadsAccounts || []);

    const [selectedThreadId, setSelectedThreadId] = useState(threadAccounts[0]?.id || '');
    const [useFb, setUseFb] = useState(true);
    const [useThreads, setUseThreads] = useState(true);

    const [isAnalyzing, setIsAnalyzing] = useState(false);
    const [result, setResult] = useState<DNALabAnalysis | null>(null);
    const [loadingStage, setLoadingStage] = useState('');
    const cardRef = useRef<HTMLDivElement>(null);

    const role = user?.role || 'user';

    const getRoleLabel = (role: UserRole) => {
        switch(role) {
            case 'starter': return 'Starter (職業裝)';
            case 'pro': return 'Pro (稀有配件)';
            case 'business': return 'Business (VIP光環)';
            case 'admin': return 'GM (神裝)';
            default: return 'Free (初始型態)';
        }
    };

    const handleAnalyze = async () => {
        if (!user) return alert("請先登入");

        // Validation
        const hasFbConfig = settings.facebookPageId && settings.facebookToken;
        const hasThreadsConfig = threadAccounts.length > 0;

        if (useFb && !hasFbConfig) return alert("無法分析 FB：請先至設定頁面連結 Facebook 粉絲專頁。");
        if (useThreads && !hasThreadsConfig) return alert("無法分析 Threads：請先連結 Threads 帳號。");
        if (!useFb && !useThreads) return alert("請至少選擇一種數據來源！");

        // [BILLING] DNA Lab: 10 Points
        const COST = 10;
        const allowed = await checkAndUseQuota(user.user_id, COST, 'DNA_LAB_ANALYSIS');
        if (!allowed) return;
        onQuotaUpdate();

        setIsAnalyzing(true);
        setResult(null);

        try {
            let combinedText = "";

            // 1. Fetch Facebook Data
            if (useFb && hasFbConfig) {
                setLoadingStage('正在掃描 Facebook 粉專 (Public Persona)...');
                try {
                    const fbPosts = await fetchRecentPostCaptions(settings.facebookPageId, settings.facebookToken, 10);
                    if (fbPosts.length > 0) {
                        combinedText += `\n\n=== [SOURCE: FACEBOOK PAGE (Public/Professional Layer)] ===\n${fbPosts.join('\n---\n')}`;
                    }
                } catch (e) {
                    console.warn("FB Fetch Failed", e);
                }
            }

            // 2. Fetch Threads Data
            if (useThreads && hasThreadsConfig) {
                setLoadingStage('正在掃描 Threads 帳號 (Inner/Chaos Persona)...');
                const targetAccount = selectedThreadId ? threadAccounts.find(a => a.id === selectedThreadId) : threadAccounts[0];
                if (targetAccount) {
                    try {
                        const posts = await fetchUserThreads(targetAccount, 15);
                        const postTexts = posts.map((p: any) => p.text).filter(Boolean);
                        if (postTexts.length > 0) {
                            combinedText += `\n\n=== [SOURCE: THREADS (Private/Authentic Layer)] ===\n${postTexts.join('\n---\n')}`;
                        }
                    } catch (e) {
                        console.warn("Threads Fetch Failed", e);
                    }
                }
            }

            if (combinedText.length < 50) throw new Error("抓取到的貼文內容過少，無法進行基因分析。");

            // 3. Analyze DNA (Gemini)
            setLoadingStage('AI 正在融合雙重人格數據...');
            const analysis = await generateDNALabAnalysis([combinedText]); // API expects array but we formatted it as one block

            // 4. Generate Visual (RPG Style)
            setLoadingStage(`正在生成 RPG 寵物 (${getRoleLabel(role)})...`);

            const prompt = buildDNALabImagePrompt(analysis.visualDescription, role);
            const imageUrl = await generateImage(prompt, role); 

            setResult({ ...analysis, imageUrl });

        } catch (e: any) {
            alert(`分析失敗: ${e.message}`);
        } finally {
            setIsAnalyzing(false);
            setLoadingStage('');
        }
    };

    const handleDownload = () => {
        if (!result?.imageUrl) return;
        const link = document.createElement('a');
        link.href = result.imageUrl;
        link.download = `AutoSocial_DNALab_${Date.now()}.png`;
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
    };

    return (
        <div className="max-w-5xl mx-auto p-4 md:p-8 space-y-8 animate-fade-in pb-20">
            {/* Header */}
            <div className="text-center space-y-2">
                <h2 className="text-3xl md:text-5xl font-black text-white tracking-tighter drop-shadow-[0_0_15px_rgba(0,242,234,0.5)]">
                    🧬 數位基因實驗室
                </h2>
                <p className="text-gray-400 font-medium tracking-widest text-xs md:text-sm uppercase">
                    Cross-Platform Persona Synthesis
                </p>
                <div className="inline-block bg-gray-800 border border-gray-600 px-4 py-1 rounded-full text-xs text-gray-300 mt-2">
                    目前會員等級：<span className="text-primary font-bold">{getRoleLabel(role)}</span>
                </div>
            </div>

            {/* Source Selection Controls */}
            <div className="bg-card p-6 rounded-2xl border border-gray-700 flex flex-col items-center gap-6">

                <div className="flex flex-wrap gap-4 justify-center">
                    {/* FB Toggle */}
                    <label className={`flex items-center gap-3 p-3 rounded-xl border cursor-pointer transition-all ${useFb ? 'bg-blue-900/30 border-blue-500' : 'bg-dark border-gray-700 opacity-50'}`}>
                        <input type="checkbox" checked={useFb} onChange={e => setUseFb(e.target.checked)} className="w-5 h-5 accent-blue-500" />
                        <div>
                            <div className="text-white font-bold text-sm">Facebook 粉專</div>
                            <div className="text-[10px] text-gray-400">來源: {settings.facebookPageId ? '已連結' : '未設定'}</div>
                        </div>
                    </label>

                    <div className="text-2xl text-gray-600 self-center">+</div>

                    {/* Threads Toggle */}
                    <label className={`flex items-center gap-3 p-3 rounded-xl border cursor-pointer transition-all ${useThreads ? 'bg-pink-900/30 border-pink-500' : 'bg-dark border-gray-700 opacity-50'}`}>
                        <input type="checkbox" checked={useThreads} onChange={e => setUseThreads(e.target.checked)} className="w-5 h-5 accent-pink-500" />
                        <div>
                            <div className="text-white font-bold text-sm">Threads 帳號</div>
                            {threadAccounts.length > 0 ? (
                                <select 
                                    value={selectedThreadId} 
                                    onClick={e => e.stopPropagation()} // Prevent toggle
                                    onChange={e => setSelectedThreadId(e.target.value)}
                                    className="bg-black/50 border border-gray-600 rounded px-2 py-1 text-[10px] text-white mt-1 outline-none"
                                >
                                    {threadAccounts.map(acc => <option key={acc.id} value={acc.id}>{acc.username}</option>)}
                                </select>
                            ) : <div className="text-[10px] text-red-400">未連結</div>}
                        </div>
                    </label>
                </div>

                <button 
                    onClick={handleAnalyze} 
                    disabled={isAnalyzing}
                    className="bg-gradient-to-r from-blue-600 via-purple-600 to-pink-600 hover:brightness-110 text-white px-8 py-3 rounded-xl font-bold shadow-lg transition-all w-full md:w-auto disabled:opacity-50 disabled:cursor-not-allowed flex items-center justify-center gap-2"
                >
                    {isAnalyzing ? (
                        <><div className="loader w-4 h-4 border-t-white"></div> {loadingStage}</>
                    ) : (
                        '🧪 開始全域融合分析 (10 點)'
                    )}
                </button>
            </div>

            {/* Result Area */}
            {result && (
                <div className="relative w-full max-w-md mx-auto" ref={cardRef}>
                    {/* The Card Container */}
                    <div className="bg-gradient-to-b from-gray-900 to-black rounded-[2rem] border-4 border-purple-500/50 shadow-[0_0_50px_rgba(168,85,247,0.3)] overflow-hidden relative">

                        {/* Decorative Header */}
                        <div className="bg-purple-900/30 p-4 border-b border-purple-500/30 flex justify-between items-center">
                            <span className="text-[10px] font-black tracking-[0.2em] text-purple-300 uppercase">AutoSocial Lab</span>
                            <div className="flex gap-1">
                                <div className="w-2 h-2 rounded-full bg-red-500"></div>
                                <div className="w-2 h-2 rounded-full bg-yellow-500"></div>
                                <div className="w-2 h-2 rounded-full bg-green-500"></div>
                            </div>
                        </div>

                        {/* Character Image */}
                        <div className="aspect-square w-full bg-white relative p-8 flex items-center justify-center overflow-hidden group">
                            {/* Background Pattern */}
                            <div className="absolute inset-0 opacity-10 bg-[url('https://www.transparenttextures.com/patterns/cubes.png')]"></div>

                            {result.imageUrl ? (
                                <img src={result.imageUrl} alt="Character" className="relative z-10 w-full h-full object-contain drop-shadow-2xl filter group-hover:scale-105 transition-transform duration-500" />
                            ) : (
                                <div className="text-black/50 font-bold">Image Gen Failed</div>
                            )}

                            {/* VIP Effect for Business Users */}
                            {role === 'business' && (
                                <div className="absolute top-4 right-4 bg-yellow-400 text-black font-black px-3 py-1 rounded-full text-xs shadow-lg animate-bounce z-20">
                                    👑 VIP USER
                                </div>
                            )}
                        </div>

                        {/* Stats Panel */}
                        <div className="p-6 space-y-6">

                            {/* Title & Name */}
                            <div className="text-center">
                                <h3 className="text-sm font-bold text-gray-400 uppercase tracking-wider mb-1">{result.species}</h3>
                                <h2 className="text-2xl font-black text-white leading-tight bg-clip-text text-transparent bg-gradient-to-r from-purple-400 to-pink-400">
                                    {result.title}
                                </h2>
                            </div>

                            {/* Stats Grid (RPG Style - Updated for Duality) */}
                            <div className="grid grid-cols-2 gap-3 text-xs">
                                <StatBar label="混沌 (Chaos)" value={result.stats.chaos} color="bg-red-500" />
                                <StatBar label="專業 (Professional)" value={result.stats.professionalism || result.stats.chill} color="bg-blue-500" />
                                <StatBar label="知識 (INT)" value={result.stats.intellect} color="bg-green-500" />
                                <StatBar label="攻擊 (ATK)" value={result.stats.aggression} color="bg-orange-500" />
                                <StatBar label="感性 (EMO)" value={result.stats.emo} color="bg-purple-500" />
                                <StatBar label="反差萌 (Duality)" value={result.stats.duality || result.stats.luck} color="bg-yellow-500" />
                            </div>

                            {/* The Roast Comment */}
                            <div className="bg-white/5 p-4 rounded-xl border border-white/10 relative">
                                <span className="absolute -top-2 left-4 text-2xl">❝</span>
                                <p className="text-gray-300 text-sm italic text-center font-medium leading-relaxed pt-2">
                                    {result.comment}
                                </p>
                                <span className="absolute -bottom-4 right-4 text-2xl text-gray-600">❞</span>
                            </div>

                            {/* Footer */}
                            <div className="text-center pt-2">
                                <p className="text-[10px] text-gray-600 font-bold uppercase tracking-widest">
                                    Powered by AutoSocial AI
                                </p>
                            </div>
                        </div>
                    </div>

                    <button onClick={handleDownload} className="mt-6 w-full text-center text-gray-400 hover:text-white text-sm underline">
                        ⭳ 保存角色圖
                    </button>
                </div>
            )}
        </div>
    );
};

const StatBar = ({ label, value, color }: { label: string, value: number, color: string }) => (
    <div className="flex flex-col gap-1">
        <div className="flex justify-between text-[10px] font-bold text-gray-400">
            <span>{label}</span>
            <span>{value || 0}</span>
        </div>
        <div className="w-full h-2 bg-gray-800 rounded-full overflow-hidden">
            <div className={`h-full ${color}`} style={{ width: `${value || 0}%` }}></div>
        </div>
    </div>
);

export default DigitalDNALab;

import React, { useState, useEffect } from 'react';
import { login, register, sendPasswordReset } from '../services/authService';

interface Props {
  onLoginSuccess: () => void;
}

const Login: React.FC<Props> = ({ onLoginSuccess }) => {
  const [mode, setMode] = useState<'LOGIN' | 'REGISTER' | 'FORGOT'>('LOGIN');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [rememberMe, setRememberMe] = useState(false);
  const [error, setError] = useState('');
  const [successMsg, setSuccessMsg] = useState('');
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    const savedEmail = localStorage.getItem('autosocial_remembered_email');
    if (savedEmail) {
      setEmail(savedEmail);
      setRememberMe(true);
    }
  }, []);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setError('');
    setSuccessMsg('');

    try {
      if (mode === 'REGISTER') {
        await register(email.trim(), password.trim());
        onLoginSuccess();
      } else if (mode === 'LOGIN') {
        await login(email.trim(), password.trim());

        // Handle Remember Me
        if (rememberMe) {
          localStorage.setItem('autosocial_remembered_email', email.trim());
        } else {
          localStorage.removeItem('autosocial_remembered_email');
        }

        onLoginSuccess();
      } else if (mode === 'FORGOT') {
        await sendPasswordReset(email.trim());
        setSuccessMsg(`密碼重設信已發送至 ${email}，請檢查信箱。`);
      }
    } catch (err: any) {
      console.error(err);
      setError(err.message || '發生錯誤');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="flex items-center justify-center min-h-screen relative overflow-hidden">
      {/* Login Card */}
      <div className="glass-card p-10 rounded-3xl w-full max-w-md animate-fade-in relative z-10 border border-white/10 shadow-[0_0_50px_rgba(0,0,0,0.5)]">
        <div className="text-center mb-8">
            <h1 className="text-4xl font-black text-white tracking-tighter mb-2">
                AUTO<span className="text-neon-cyan">SOCIAL</span>
            </h1>
            <p className="text-sm font-bold text-gray-400 tracking-[0.2em] uppercase">
                AI 社群自動化中控台
            </p>
        </div>

        <h2 className="text-2xl font-bold text-center text-white mb-2">
          {mode === 'REGISTER' ? '建立帳戶' : mode === 'FORGOT' ? '重設密碼' : '歡迎回來'}
        </h2>

        <div className="text-gray-400 text-center mb-8 text-sm">
          {mode === 'REGISTER' ? '開始您的自動化之旅' : mode === 'FORGOT' ? '我們會發送重設連結給您' : (
             <>
                一篇貼文最低 <span className="text-primary font-bold">NT$3</span>，立即體驗全自動社群經營！
             </>
          )}
        </div>

        <form onSubmit={handleSubmit} className="space-y-5">
          <div>
            <label className="block text-xs font-bold text-gray-500 mb-1 uppercase tracking-wider">Email / Username</label>
            <input 
              type="text" 
              name="email"
              required
              autoComplete="username"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              className="w-full p-4 rounded-xl outline-none text-white font-medium"
              placeholder="name@example.com"
            />
          </div>

          {mode !== 'FORGOT' && (
            <div>
              <label className="block text-xs font-bold text-gray-500 mb-1 uppercase tracking-wider">Password</label>
              <input 
                type="password"
                name="password" 
                required
                autoComplete={mode === 'REGISTER' ? "new-password" : "current-password"}
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                className="w-full p-4 rounded-xl outline-none text-white font-medium"
              />
            </div>
          )}

          {mode === 'LOGIN' && (
            <div className="flex items-center gap-2">
              <input 
                type="checkbox" 
                id="rememberMe"
                checked={rememberMe}
                onChange={(e) => setRememberMe(e.target.checked)}
                className="w-4 h-4 rounded border-gray-600 bg-black/30 text-primary focus:ring-primary cursor-pointer"
              />
              <label htmlFor="rememberMe" className="text-sm text-gray-400 cursor-pointer select-none">
                記住帳號 (Remember Me)
              </label>
            </div>
          )}

          {error && <div className="text-red-400 text-xs font-bold text-center bg-red-900/20 p-3 rounded border border-red-900/50">{error}</div>}
          {successMsg && <div className="text-green-400 text-xs font-bold text-center bg-green-900/20 p-3 rounded border border-green-900/50">{successMsg}</div>}

          <button 
            type="submit" 
            disabled={loading}
