            // 優先權：如果存在後門 Session 則覆蓋 Firebase 狀態
            if (localStorage.getItem(SESSION_KEY) === PREVIEW_ADMIN_ID) {
                checkMockAndBackdoor();
                return;
            }

            if (firebaseUser) {
                const profile = await getUserProfile(firebaseUser.uid);
                if (profile && profile.isSuspended) {
                    await logout();
                    callback(null);
                } else {
                    callback({ uid: firebaseUser.uid, email: firebaseUser.email || '' });
                }
            } else {
                callback(null);
            }
        });
    }

    if (typeof window !== 'undefined') {
        window.addEventListener('auth_state_change', checkMockAndBackdoor);
        setTimeout(checkMockAndBackdoor, 0);
    }

    return () => {
        if (typeof window !== 'undefined') window.removeEventListener('auth_state_change', checkMockAndBackdoor);
    };
};

export const sendPasswordReset = async (email: string) => {
    if (!isMock) await auth.sendPasswordResetEmail(email);
};

export const exchangeThreadsAuth = async (code: string, redirectUri: string) => {
    if (isMock) {
        return { 
            token: 'mock_threads_long_token_' + Date.now(), 
            userId: 'mock_user_123',
            username: 'mock_threads_user'
        };
    }

    const res = await fetch('/api/threads', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ action: 'exchange', code, redirectUri })
    });

    const data = await res.json();
    if (!data.success) throw new Error(data.error || 'Token exchange failed');
    return data.data;
};

import React, { useState, useEffect } from 'react';
import { login, register, sendPasswordReset } from '../services/authService';

interface Props {
  onLoginSuccess: () => void;
}

const Login: React.FC<Props> = ({ onLoginSuccess }) => {
  const [mode, setMode] = useState<'LOGIN' | 'REGISTER' | 'FORGOT'>('LOGIN');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [rememberMe, setRememberMe] = useState(false);
  const [error, setError] = useState('');
  const [successMsg, setSuccessMsg] = useState('');
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    const savedEmail = localStorage.getItem('autosocial_remembered_email');
    if (savedEmail) {
      setEmail(savedEmail);
      setRememberMe(true);
    }
  }, []);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setError('');
    setSuccessMsg('');

    try {
      if (mode === 'REGISTER') {
        await register(email.trim(), password.trim());
        onLoginSuccess();
      } else if (mode === 'LOGIN') {
        await login(email.trim(), password.trim());

        // Handle Remember Me
        if (rememberMe) {
          localStorage.setItem('autosocial_remembered_email', email.trim());
        } else {
          localStorage.removeItem('autosocial_remembered_email');
        }

        onLoginSuccess();
      } else if (mode === 'FORGOT') {
        await sendPasswordReset(email.trim());
        setSuccessMsg(`密碼重設信已發送至 ${email}，請檢查信箱。`);
      }
    } catch (err: any) {
      console.error(err);
      setError(err.message || '發生錯誤');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="flex items-center justify-center min-h-screen relative overflow-hidden">
      {/* Login Card */}
      <div className="glass-card p-10 rounded-3xl w-full max-w-md animate-fade-in relative z-10 border border-white/10 shadow-[0_0_50px_rgba(0,0,0,0.5)]">
        <div className="text-center mb-8">
