const handleFirestoreError = (e: any, action: string) => {
    console.error(`Firestore Error [${action}]:`, e);
    if (e.code === 'permission-denied') {
        alert(`❌ 權限不足：請確保已在 Firebase Console 設定 Security Rules。\n操作：${action}`);
