            const hasFbConfig = settings.facebookPageId && settings.facebookToken;
            const hasThreadsConfig = threadAccounts.length > 0;
            if (useFb && !hasFbConfig) return alert("無法分析 FB：請先至設定頁面連結 Facebook 粉絲專頁。");
            if (useThreads && !hasThreadsConfig) return alert("無法分析 Threads：請先連結 Threads 帳號。");
            if (!useFb && !useThreads) return alert("請至少選擇一種數據來源！");
        }

        const COST = 10;
        const allowed = await checkAndUseQuota(user.user_id, COST, 'DNA_LAB_ANALYSIS');
        if (!allowed) return;
        onQuotaUpdate();

        setIsAnalyzing(true);
        setResult(null);

        try {
            let combinedText = "";

            if (isCreatorMode) {
                if (useFb) combinedText += `\n\n=== [SOURCE: FACEBOOK PAGE] ===\n${mockFbText}`;
                if (useThreads) combinedText += `\n\n=== [SOURCE: THREADS] ===\n${mockThreadsText}`;
                setLoadingStage('正在讀取模擬數據...');
                await new Promise(r => setTimeout(r, 1200));
            } else {
                if (useFb) {
                    setLoadingStage('正在掃描 Facebook 粉專...');
                    try {
                        const fbPosts = await fetchRecentPostCaptions(settings.facebookPageId, settings.facebookToken, 10);
                        if (fbPosts.length > 0) combinedText += `\n\n=== [SOURCE: FB] ===\n${fbPosts.join('\n---\n')}`;
                    } catch (e) { console.warn("FB Fetch Failed", e); }
                }
                if (useThreads) {
                    setLoadingStage('正在掃描 Threads 帳號...');
                    const targetAccount = selectedThreadId ? threadAccounts.find(a => a.id === selectedThreadId) : threadAccounts[0];
                    if (targetAccount) {
                        try {
                            const posts = await fetchUserThreads(targetAccount, 15);
                            const postTexts = posts.map((p: any) => p.text).filter(Boolean);
                            if (postTexts.length > 0) combinedText += `\n\n=== [SOURCE: THREADS] ===\n${postTexts.join('\n---\n')}`;
                        } catch (e) { console.warn("Threads Fetch Failed", e); }
                    }
                }
            }

            if (combinedText.length < 10) throw new Error("抓取到的內容過少，無法分析。");

            setLoadingStage('AI 正在融合雙重人格數據...');
            let analysis: DNALabAnalysis;
            try {
                analysis = await generateDNALabAnalysis([combinedText]);
            } catch (apiError) {
                if (isCreatorMode) {
                    analysis = { ...FALLBACK_ANALYSIS, stats: { ...FALLBACK_ANALYSIS.stats, chaos: Math.floor(Math.random()*40 + 60) } };
                } else { throw apiError; }
            }

            setLoadingStage(`正在生成 RPG 寵物形象...`);
            const prompt = buildDNALabImagePrompt(analysis.visualDescription, role);
            let imageUrl = '';
            try {
                imageUrl = await generateImage(prompt, role);
            } catch (imgError) {
                imageUrl = `https://image.pollinations.ai/prompt/${encodeURIComponent(prompt)}?n=${Date.now()}&model=flux`;
            }

            setResult({ ...analysis, imageUrl });

        } catch (e: any) {
            alert(`分析失敗: ${e.message}`);
        } finally {
            setIsAnalyzing(false);
            setLoadingStage('');
        }
    };

    const handleDownload = () => {
        if (!result?.imageUrl) return;
        window.open(result.imageUrl, '_blank');
    };

    return (
        <div className="max-w-5xl mx-auto p-4 md:p-8 space-y-8 animate-fade-in pb-24 relative">
            {/* Header with fixed simulation toggle */}
            <div className="flex flex-col md:flex-row justify-between items-center gap-6 border-b border-gray-800 pb-8 relative z-20">
                <div className="text-center md:text-left">
                    <h2 className="text-4xl md:text-5xl font-black text-white tracking-tighter drop-shadow-[0_0_15px_rgba(0,242,234,0.4)]">🧬 數位基因實驗室</h2>
                    <p className="text-gray-500 font-bold tracking-[0.3em] uppercase text-[10px] mt-2">Persona Synthesis Engine v2.0</p>
                </div>

                <button 
                    onClick={() => setIsCreatorMode(!isCreatorMode)}
                    className={`relative px-6 py-3 rounded-2xl font-black text-xs transition-all flex items-center gap-3 overflow-hidden border-2 group active:scale-95 ${
                        isCreatorMode 
                        ? 'bg-yellow-500/10 border-yellow-500 text-yellow-400 shadow-[0_0_20px_rgba(234,179,8,0.2)]' 
                        : 'bg-gray-800/50 border-gray-700 text-gray-500 hover:border-gray-500'
                    }`}
                >
                    <span className={`w-2 h-2 rounded-full ${isCreatorMode ? 'bg-yellow-400 animate-pulse shadow-[0_0_8px_#facc15]' : 'bg-gray-600'}`}></span>
                    {isCreatorMode ? '⚡ 模擬模式已啟動' : '🧪 啟動模擬模式'}
                    {isCreatorMode && <div className="absolute inset-0 bg-yellow-400/5 group-hover:bg-yellow-400/10"></div>}
                </button>
            </div>

            {/* Source Selection & Custom Editor */}
            <div className="glass-card p-10 rounded-[3rem] space-y-8 relative overflow-hidden">
                <div className="absolute top-0 right-0 w-64 h-64 bg-primary/5 blur-[100px] pointer-events-none"></div>

                <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
                    {/* FB Column */}
                    <div className={`space-y-4 p-6 rounded-3xl border transition-all ${useFb ? 'bg-blue-900/10 border-blue-500/50 shadow-[0_0_20px_rgba(59,130,246,0.1)]' : 'bg-black/20 border-gray-800 opacity-40 grayscale'}`}>
                        <label className="flex items-center gap-3 cursor-pointer group">
                            <input type="checkbox" checked={useFb} onChange={e => setUseFb(e.target.checked)} className="w-6 h-6 rounded-lg accent-blue-500" />
                            <span className="text-lg font-black text-white group-hover:text-blue-400 transition-colors">f Facebook (外在人格)</span>
                        </label>
                        {isCreatorMode && useFb && (
                            <div className="animate-fade-in space-y-2">
                                <label className="text-[10px] text-blue-400 font-bold uppercase tracking-widest">模擬貼文數據 (專業/公眾)</label>
                                <textarea value={mockFbText} onChange={e => setMockFbText(e.target.value)} className="w-full h-40 bg-black/60 border border-blue-900/50 rounded-2xl p-4 text-xs text-blue-100 resize-none outline-none focus:border-blue-400 custom-scrollbar" />
                            </div>
                        )}
                    </div>

                    {/* Threads Column */}
                    <div className={`space-y-4 p-6 rounded-3xl border transition-all ${useThreads ? 'bg-pink-900/10 border-pink-500/50 shadow-[0_0_20px_rgba(236,72,153,0.1)]' : 'bg-black/20 border-gray-800 opacity-40 grayscale'}`}>
                        <label className="flex items-center gap-3 cursor-pointer group">
                            <input type="checkbox" checked={useThreads} onChange={e => setUseThreads(e.target.checked)} className="w-6 h-6 rounded-lg accent-pink-500" />
                            <span className="text-lg font-black text-white group-hover:text-pink-400 transition-colors">@ Threads (內在人格)</span>
                        </label>
                        {isCreatorMode && useThreads && (
                            <div className="animate-fade-in space-y-2">
                                <label className="text-[10px] text-pink-400 font-bold uppercase tracking-widest">模擬脆文數據 (混沌/真實)</label>
                                <textarea value={mockThreadsText} onChange={e => setMockThreadsText(e.target.value)} className="w-full h-40 bg-black/60 border border-pink-900/50 rounded-2xl p-4 text-xs text-pink-100 resize-none outline-none focus:border-pink-400 custom-scrollbar" />
                            </div>
                        )}
                    </div>
                </div>

                <div className="pt-6 flex flex-col items-center gap-4">
                    <button 
                        onClick={handleAnalyze} 
                        disabled={isAnalyzing}
                        className="bg-gradient-to-r from-blue-600 via-purple-600 to-pink-600 text-white px-16 py-5 rounded-[2rem] font-black text-xl shadow-2xl hover:scale-105 active:scale-95 transition-all disabled:opacity-50 disabled:scale-100 disabled:grayscale flex items-center gap-4 group"
                    >
                        {isAnalyzing ? (
                            <>
                                <div className="loader w-6 h-6 border-t-white"></div>
                                <span className="animate-pulse">{loadingStage}</span>
                            </>
                        ) : (
                            <>
                                🧪 開始融合分析 <span className="text-sm font-bold bg-white/20 px-3 py-1 rounded-full">10 點數</span>
                            </>
                        )}
                    </button>
                    <p className="text-[10px] text-gray-600 font-bold uppercase tracking-widest">AI will synthesize your digital twin into a fantasy creature</p>
                </div>
            </div>

            {/* Result Display */}
            {result && (
                <div className="max-w-2xl mx-auto animate-fade-in pt-10">
                    <div className="bg-gradient-to-b from-gray-900 to-black rounded-[3rem] border-4 border-white/5 shadow-[0_0_50px_rgba(0,0,0,0.8)] overflow-hidden">
                        <div className="aspect-square bg-white p-10 relative flex items-center justify-center">
                            <div className="absolute inset-0 opacity-5 bg-[url('https://www.transparenttextures.com/patterns/cubes.png')]"></div>
                            <img src={result.imageUrl} alt="RPG Avatar" className="relative z-10 w-full h-full object-contain drop-shadow-[0_20px_40px_rgba(0,0,0,0.4)] hover:scale-110 transition-transform duration-700" />
                        </div>
                        <div className="p-10 space-y-8">
                            <div className="text-center space-y-1">
                                <h3 className="text-[10px] font-black text-gray-500 uppercase tracking-[0.3em]">{result.species}</h3>
                                <h2 className="text-4xl font-black text-white bg-clip-text text-transparent bg-gradient-to-r from-cyan-400 via-purple-400 to-pink-400">{result.title}</h2>
                            </div>

                            <div className="grid grid-cols-2 gap-x-8 gap-y-6">
                                <StatBar label="混沌 (Chaos)" value={result.stats.chaos || 0} color="bg-red-500" />
                                <StatBar label="專業 (PR)" value={result.stats.professionalism || 0} color="bg-blue-500" />
                                <StatBar label="智力 (INT)" value={result.stats.intellect || 0} color="bg-green-500" />
                                <StatBar label="感性 (EMO)" value={result.stats.emo || 0} color="bg-purple-500" />
                            </div>

                            <div className="bg-white/5 p-8 rounded-3xl border border-white/10 relative">
                                <span className="absolute -top-3 left-6 bg-gray-900 px-3 text-[10px] font-black text-yellow-500 uppercase tracking-widest">Psychological Roast</span>
                                <p className="text-gray-200 text-lg italic leading-relaxed text-center font-medium">"{result.comment}"</p>
                            </div>

                            <button onClick={handleDownload} className="w-full py-4 bg-white text-black rounded-2xl font-black text-sm uppercase tracking-widest hover:bg-gray-200 transition-all flex items-center justify-center gap-2 shadow-xl">
                                ⭳ 保存我的數位基因圖鑑
                            </button>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

const StatBar = ({ label, value, color }: { label: string, value: number, color: string }) => (
    <div className="flex flex-col gap-2">
        <div className="flex justify-between font-black text-[10px] text-gray-500 uppercase tracking-widest">
            <span>{label}</span>
            <span className="text-white">{value}</span>
        </div>
        <div className="w-full h-2 bg-gray-800 rounded-full overflow-hidden shadow-inner">
            <div className={`h-full ${color} transition-all duration-1000 ease-out shadow-[0_0_10px_rgba(255,255,255,0.1)]`} style={{ width: `${value}%` }}></div>
        </div>
    </div>
);

export default DigitalDNALab;

import React, { useState, useEffect } from 'react';
import { 
  getAllUsers, generateAdminKey, 
  getDashboardStats, getSystemLogs, getSystemConfig, updateSystemConfig, 
  getUserReports
} from '../services/authService';
import { getApiServiceStatus } from '../services/geminiService';
import { db, isMock } from '../services/firebase';
import { UserProfile, UserRole, DashboardStats, LogEntry, SystemConfig, UserReport } from '../types';
import { SecurityActionModal } from './admin/SecurityActionModal';
import { ApiMonitor } from './admin/ApiMonitor';
import { UserTable } from './admin/UserTable';

interface Props {
  currentUser: UserProfile;
}

const TAB_NAMES: Record<string, string> = {
    dashboard: '儀表板',
    users: '會員管理',
    keys: '金鑰生成',
    api_monitor: '流量監控',
    reports: '回報單',
    system: '系統設定'
};

const AdminPanel: React.FC<Props> = ({ currentUser }) => {
  const [activeTab, setActiveTab] = useState<'dashboard' | 'users' | 'api_monitor' | 'reports' | 'system' | 'keys'>('dashboard');

  // State
  const [stats, setStats] = useState<DashboardStats | null>(null);
  const [users, setUsers] = useState<UserProfile[]>([]);
  const [reports, setReports] = useState<UserReport[]>([]);
  const [apiUsage, setApiUsage] = useState<any>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [apiStatus, setApiStatus] = useState<{ 
      keyStatus: boolean[]; 
      providers: { openai: boolean; ideogram: boolean; grok: boolean; };
  }>({ 
      keyStatus: [], 
      providers: { openai: false, ideogram: false, grok: false } 
  });
  const [securityTarget, setSecurityTarget] = useState<{uid: string, type: 'DOWNLOAD'|'DELETE'} | null>(null);
  const [logs, setLogs] = useState<LogEntry[]>([]);
  const [config, setConfig] = useState<SystemConfig>({ maintenanceMode: false, dryRunMode: false });
  const [generatedKey, setGeneratedKey] = useState('');

  useEffect(() => {
    loadAllData();
  }, []);

  useEffect(() => {
      if (activeTab === 'api_monitor') {
          loadApiUsage();
          const timer = setInterval(loadApiUsage, 10000); // 延長為10秒刷新一次，降低API負荷
          return () => clearInterval(timer);
      }
  }, [activeTab]);

  const loadAllData = async () => {
    setIsLoading(true);
    try {
        const statsData = await getDashboardStats();
        const usersData = await getAllUsers();
        const reportsData = await getUserReports();
        const configData = getSystemConfig();

        setStats(statsData);
        setUsers(usersData);
        setReports(reportsData);
        setConfig(configData);
        setLogs(getSystemLogs());
    } catch (e) {
        console.error("Admin Load Error:", e);
    } finally {
        setIsLoading(false);
    }
  };

  const loadApiUsage = async () => {
      const statusData = await getApiServiceStatus();
      setApiStatus(statusData);

      if (isMock) {
          setApiUsage({ key_1: 1250, key_2: 890, key_3: 450, key_4: 120, key_5: 5, total_calls: 2715 });
          return;
      }
      try {
          const doc = await db.collection('system_stats').doc('api_usage').get();
          if (doc.exists) setApiUsage(doc.data());
      } catch (e) { console.error("Load API Usage failed", e); }
  };

  const handleGenerateKey = async (type: 'RESET_QUOTA' | 'UPGRADE_ROLE', role?: UserRole) => {
    const key = await generateAdminKey(currentUser.user_id, type, role);
    setGeneratedKey(key);
    loadAllData();
  };

  const handleGenerateFeatureKey = async (feature: 'ANALYTICS' | 'AUTOMATION' | 'SEO' | 'THREADS') => {
    const key = await generateAdminKey(currentUser.user_id, 'UNLOCK_FEATURE', undefined, feature);
    setGeneratedKey(key);
    loadAllData();
  };

  const handleGeneratePointsKey = async (amount: number) => {
    const key = await generateAdminKey(currentUser.user_id, 'ADD_POINTS', undefined, undefined, amount);
    setGeneratedKey(key);
    loadAllData();
  };

  const toggleDryRun = () => { updateSystemConfig({ dryRunMode: !config.dryRunMode }); loadAllData(); };
  const toggleMaintenance = () => { updateSystemConfig({ maintenanceMode: !config.maintenanceMode }); loadAllData(); };

  if (isLoading && users.length === 0) {
      return (
          <div className="h-96 flex flex-col items-center justify-center gap-4 text-gray-500">
              <div className="loader border-t-primary scale-125"></div>
              <p className="font-bold animate-pulse tracking-widest uppercase text-xs">Loading Command Center Data...</p>
          </div>
      );
  }

  return (
    <div className="max-w-7xl mx-auto p-4 space-y-6 animate-fade-in pb-24 pt-4">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
            <h2 className="text-4xl font-black text-white tracking-tighter">系統管理中控台</h2>
            <p className="text-[10px] text-gray-500 font-bold uppercase tracking-[0.3em] mt-1">Admin Command & Control Pool</p>
        </div>
        <div className="flex gap-2">
           <button onClick={loadAllData} className="px-4 py-2 bg-gray-800 hover:bg-gray-700 text-white rounded-xl text-xs font-bold transition-all border border-gray-700">↻ 立即刷新</button>
           {config.dryRunMode && <span className="px-4 py-2 bg-yellow-600/20 text-yellow-400 border border-yellow-600/50 rounded-xl text-xs font-bold animate-pulse">🧪 模擬模式</span>}
           {config.maintenanceMode && <span className="px-4 py-2 bg-red-600/20 text-red-400 border border-red-600/50 rounded-xl text-xs font-bold animate-pulse">🚧 維護中</span>}
        </div>
      </div>

      <div className="flex border-b border-gray-800 overflow-x-auto gap-2 py-2">
        {Object.keys(TAB_NAMES).map(tabKey => (
            <button 
                key={tabKey} 
                onClick={() => setActiveTab(tabKey as any)} 
                className={`px-6 py-3 font-black text-xs uppercase tracking-widest transition-all rounded-xl ${activeTab === tabKey ? 'bg-primary/10 text-primary border border-primary/20 shadow-[0_0_15px_rgba(0,242,234,0.1)]' : 'text-gray-500 hover:text-white hover:bg-white/5'}`}
            >
                {TAB_NAMES[tabKey]}
            </button>
        ))}
      </div>

      <div className="pt-4">
        {activeTab === 'dashboard' && stats && (
            <div className="space-y-6">
                <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
                    <DashboardCard label="總會員數" value={stats.totalUsers} icon="👥" color="text-white" />
                    <DashboardCard label="今日活躍 (DAU)" value={stats.activeUsersToday} icon="🔥" color="text-green-400" />
                    <DashboardCard label="今日 API 負載" value={stats.totalApiCallsToday} icon="⚡" color="text-blue-400" />
                    <DashboardCard label="待處理回報" value={reports.filter(r => r.status === 'OPEN').length} icon="🚨" color="text-red-400" />
                </div>
            </div>
        )}

        {activeTab === 'users' && (
            <div className="animate-fade-in">
                <UserTable users={users} onRefresh={loadAllData} onSecurityAction={(uid, type) => setSecurityTarget({uid, type})} />
            </div>
        )}

        {activeTab === 'keys' && (
            <div className="glass-card p-10 rounded-[2.5rem] space-y-10 animate-fade-in">
                <h3 className="text-2xl font-black text-white flex items-center gap-3">
                    <span className="p-2 bg-yellow-500/20 rounded-xl text-yellow-400 text-lg">🔑</span>
                    金鑰生成引擎 (Key Factory)
                </h3>

                <div className="grid grid-cols-1 lg:grid-cols-2 gap-12">
                    <div className="space-y-8">
                        <div>
                            <p className="text-[10px] text-gray-500 mb-4 uppercase tracking-[0.2em] font-black">身份與權限升級</p>
                            <div className="flex flex-wrap gap-2">
                                <KeyBtn onClick={() => handleGenerateKey('UPGRADE_ROLE', 'starter')} label="Starter" color="bg-green-700" />
                                <KeyBtn onClick={() => handleGenerateKey('UPGRADE_ROLE', 'pro')} label="Pro" color="bg-purple-700" />
                                <KeyBtn onClick={() => handleGenerateKey('UPGRADE_ROLE', 'business')} label="Business" color="bg-yellow-700" />
                                <KeyBtn onClick={() => handleGenerateKey('RESET_QUOTA')} label="Reset Quota" color="bg-gray-700" />
                            </div>
                        </div>
                        <div>
                            <p className="text-[10px] text-gray-500 mb-4 uppercase tracking-[0.2em] font-black">功能模組解鎖</p>
                            <div className="flex flex-wrap gap-2">
                                {['ANALYTICS', 'AUTOMATION', 'SEO', 'THREADS'].map(f => (
                                    <KeyBtn key={f} onClick={() => handleGenerateFeatureKey(f as any)} label={`Unlock ${f}`} color="bg-blue-900/60" />
                                ))}
                            </div>
                        </div>
                    </div>

                    <div className="bg-gradient-to-br from-gray-800 to-gray-900 p-8 rounded-[2rem] border border-yellow-500/20 shadow-xl">
                        <p className="text-[10px] text-yellow-400 mb-4 uppercase tracking-[0.2em] font-black flex items-center gap-2">
                            💰 點數紅包生成器
                        </p>
                        <div className="flex flex-col gap-3">
                            <PointsBtn onClick={() => handleGeneratePointsKey(30)} amount={30} />
                            <PointsBtn onClick={() => handleGeneratePointsKey(50)} amount={50} />
                            <PointsBtn onClick={() => handleGeneratePointsKey(100)} amount={100} />
                        </div>
                    </div>
                </div>

                {generatedKey && (
                    <div className="mt-10 p-10 bg-black/60 border border-green-500/50 rounded-[2rem] text-center space-y-4 animate-pulse-slow">
                        <p className="text-green-400 font-black uppercase tracking-widest text-xs">✅ Generation Success! Copy the code below:</p>
                        <p className="text-5xl font-mono text-white select-all tracking-tighter font-black drop-shadow-[0_0_15px_rgba(255,255,255,0.2)]">{generatedKey}</p>
                        <p className="text-[10px] text-gray-600 font-bold uppercase italic">* Valid for 24 Hours. Single Use Only.</p>
                    </div>
                )}
            </div>
        )}

        {activeTab === 'api_monitor' && <ApiMonitor apiUsage={apiUsage} apiStatus={apiStatus} />}

        {activeTab === 'reports' && (
            <div className="glass-card p-8 rounded-[2.5rem] space-y-6">
                <h3 className="text-2xl font-black text-white flex items-center gap-3">🚨 回報單中心</h3>
                {reports.length === 0 ? <div className="py-20 text-center text-gray-600 italic">目前無待處理事項。</div> : (
                    <div className="grid grid-cols-1 gap-4">
                        {reports.map((r) => (
                            <div key={r.id} className="bg-black/30 p-6 rounded-2xl border border-gray-800 hover:border-red-500/30 transition-all">
                                <div className="flex justify-between items-start mb-4">
                                    <div>
                                        <span className="font-black text-white">{r.userEmail}</span>
                                        <span className="text-[10px] text-gray-600 ml-3 font-mono">{new Date(r.timestamp).toLocaleString()}</span>
                                    </div>
                                    <span className="bg-red-900/30 text-red-400 text-[10px] px-3 py-1 rounded-full font-black uppercase tracking-tighter border border-red-900/50">{r.status}</span>
                                </div>
                                <p className="text-sm text-gray-300 mb-4 bg-dark p-4 rounded-xl shadow-inner border border-white/5">{r.description}</p>
                                <div className="text-[9px] text-gray-600 font-mono flex gap-4 uppercase tracking-widest">
                                    <span>View: {r.currentView}</span>
                                    <span>UA: {r.userAgent.substring(0, 50)}...</span>
                                </div>
                            </div>
                        ))}
                    </div>
                )}
            </div>
        )}

        {activeTab === 'system' && (
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
                <div className="glass-card p-8 rounded-[2.5rem] space-y-6">
                    <h3 className="text-xl font-black text-white flex items-center gap-2 uppercase tracking-wider">🔧 核心系統控制</h3>
                    <div className="space-y-4">
                        <SystemToggle label="🧪 模擬模式 (Dry Run)" desc="開啟後不扣除真實配額，不調用外部 API。" active={config.dryRunMode} onToggle={toggleDryRun} />
                        <SystemToggle label="🚧 維護模式 (Maintenance)" desc="開啟後一般用戶將被阻擋登入。" active={config.maintenanceMode} onToggle={toggleMaintenance} />
                    </div>
                </div>
                <div className="glass-card p-8 rounded-[2.5rem] space-y-6 h-[600px] flex flex-col">
                    <h3 className="text-xl font-black text-white flex items-center gap-2 uppercase tracking-wider">📜 終端日誌 (Terminal Logs)</h3>
                    <div className="flex-1 overflow-y-auto bg-black/50 p-4 rounded-2xl border border-gray-800 font-mono text-[10px] custom-scrollbar">
                        {logs.length === 0 ? <p className="text-gray-700 italic">No events recorded in this session.</p> : logs.map(l => (
                            <div key={l.id} className="mb-3 pb-3 border-b border-gray-900 last:border-0 opacity-80">
                                <div className="flex gap-2 mb-1">
                                    <span className="text-gray-600">[{new Date(l.timestamp).toLocaleTimeString()}]</span>
                                    <span className={`font-black ${l.status === 'error' ? 'text-red-500' : 'text-blue-500'}`}>{l.status.toUpperCase()}</span>
                                    <span className="text-gray-300">{l.action}</span>
                                </div>
                                <div className="pl-4 text-gray-500">{l.userEmail}: {l.details}</div>
                            </div>
                        ))}
                    </div>
                </div>
            </div>
        )}
      </div>

      {securityTarget && <SecurityActionModal targetUserId={securityTarget.uid} actionType={securityTarget.type} onClose={() => setSecurityTarget(null)} />}
    </div>
  );
};

