import { db, isMock } from './firebase';
import { getCurrentUser } from './authService';
import { QueueState } from '../types';

const MAX_CONCURRENCY = 3; 
const QUEUE_COLLECTION = 'api_queue';
const QUEUE_TIMEOUT_MS = 60 * 1000 * 5; 

let activeListener: (() => void) | null = null;
let currentQueueState: QueueState = {
    isQueuing: false, 
    position: 0, 
    totalWaiting: 0,
    currentAction: ''
};
const subscribers: ((state: QueueState) => void)[] = [];

const notifySubscribers = () => {
    subscribers.forEach(cb => cb({ ...currentQueueState }));
};

export const subscribeToQueue = (callback: (state: QueueState) => void) => {
    subscribers.push(callback);
    callback({ ...currentQueueState }); 
    return () => {
        const idx = subscribers.indexOf(callback);
        if (idx > -1) subscribers.splice(idx, 1);
    };
};

/**
 * 商業化修正：不再提供無限循環的 99 人模擬
 */
export const executeWithQueue = async <T>(
    actionName: string, 
    apiCall: () => Promise<T>
): Promise<T> => {
    // 如果是 Mock 或開發模式，直接執行，不進入排隊 UI
    if (isMock) {
        return apiCall();
    }

    const user = getCurrentUser();
    const userId = user ? user.uid : 'anonymous';

    let docRef: any;
    try {
        // 嘗試在 Firestore 建立排隊票券
        docRef = await db.collection(QUEUE_COLLECTION).add({
            userId,
            action: actionName,
            createdAt: Date.now(),
            expiresAt: Date.now() + QUEUE_TIMEOUT_MS,
            status: 'waiting'
        });
    } catch (e: any) {
        console.warn("[Queue] 無法建立隊列票券，切換至併發模式:", e.message);
        return apiCall(); // 降級處理：直接執行
    }

    // 初始化 UI 狀態：從 1 開始而非 99
    currentQueueState = { isQueuing: true, position: 1, totalWaiting: 1, currentAction: actionName };
    notifySubscribers();

    return new Promise<T>((resolve, reject) => {
        const cleanup = () => {
            if (activeListener) { activeListener(); activeListener = null; }
            docRef.delete().catch(() => {}); 
            currentQueueState = { isQueuing: false, position: 0, totalWaiting: 0, currentAction: '' };
            notifySubscribers();
        };

        // 監聽排隊狀況
        activeListener = db.collection(QUEUE_COLLECTION)
            .where('expiresAt', '>', Date.now()) 
            .orderBy('createdAt', 'asc') 
            .onSnapshot(async (snapshot: any) => {
                const allDocs = snapshot.docs;
                const myIndex = allDocs.findIndex((d: any) => d.id === docRef.id);

                if (myIndex === -1) {
                    cleanup();
                    apiCall().then(resolve).catch(reject);
                    return;
                }

                // 更新 UI 上的排隊名次
                currentQueueState = { 
                    isQueuing: true, 
                    position: myIndex + 1, 
                    totalWaiting: allDocs.length, 
                    currentAction: actionName 
                };
                notifySubscribers();

                // 如果輪到自己（名次小於併發限制）
                if (myIndex < MAX_CONCURRENCY) {
                    if (activeListener) { activeListener(); activeListener = null; }
                    try {
                        const result = await apiCall();
                        resolve(result);
                    } catch (e) {
                        reject(e);
                    } finally {
                        cleanup();
                    }
                }
            }, (error: any) => {
                console.error("[Queue] 監聽異常，強制執行:", error.message);
                cleanup();
                apiCall().then(resolve).catch(reject);
            });
    });
};

import { auth, db, isMock } from '../firebase';
import { createUserProfile, getUserProfile } from './user';
import { MockStore } from '../mockStore';
import { UserProfile } from '../../types';

const SESSION_KEY = 'autosocial_session_uid';

export const getCurrentUser = () => {
    const localUid = typeof window !== 'undefined' ? localStorage.getItem(SESSION_KEY) : null;

    // 真實 Firebase Auth
    if (!isMock && auth.currentUser) {
        return auth.currentUser;
    }

    // 商業化修正：僅在 Mock 模式下允許讀取本地 Session
    if (localUid && isMock) {
         const u = MockStore.getUser(localUid);
         return { uid: localUid, email: u ? u.email : 'demo@example.com' };
    }
    return null;
};

export const login = async (email: string, pass: string) => {
    // 商業化修正：不再提供硬編碼的 admin 密碼
    // 所有用戶（包括管理員）必須通過 Firebase Authentication 註冊與登入

    if (!isMock) {
        const cred = await auth.signInWithEmailAndPassword(email, pass);
        localStorage.setItem(SESSION_KEY, cred.user!.uid);
        return { user: cred.user };
    } 

    // 開發者用的 Mock 登入邏輯（僅在沒設定 Firebase 時生效）
    const user = MockStore.findUserByEmail(email);
    if (user) {
        localStorage.setItem(SESSION_KEY, user.user_id);
        window.dispatchEvent(new Event('auth_state_change'));
        return { user: { uid: user.user_id, email: user.email } };
    }

    return await register(email, pass);
};

export const register = async (email: string, pass: string) => {
    if (!isMock) {
        const cred = await auth.createUserWithEmailAndPassword(email, pass);
        await createUserProfile({ uid: cred.user!.uid, email: email });
        localStorage.setItem(SESSION_KEY, cred.user!.uid);
        return { user: cred.user };
    } 

    const uid = 'user_' + Date.now();
    await createUserProfile({ uid, email });
    localStorage.setItem(SESSION_KEY, uid);
    window.dispatchEvent(new Event('auth_state_change'));
    return { user: { uid, email } };
};

export const logout = async () => {
    localStorage.removeItem(SESSION_KEY);
    window.dispatchEvent(new Event('auth_state_change'));
    if (!isMock) await auth.signOut();
};

export const subscribeAuth = (callback: (user: { uid: string, email: string } | null) => void) => {
    if (!isMock) {
        return auth.onAuthStateChanged(async (firebaseUser: any) => {
            if (firebaseUser) {
                const profile = await getUserProfile(firebaseUser.uid);
                if (profile && profile.isSuspended) {
                    await logout();
                    callback(null);
                } else {
                    callback({ uid: firebaseUser.uid, email: firebaseUser.email || '' });
                }
            } else {
                callback(null);
            }
        });
    }

    const checkMock = () => {
         const uid = localStorage.getItem(SESSION_KEY);
         if (uid && isMock) {
             const u = MockStore.getUser(uid);
             callback({ uid: uid, email: u ? u.email : 'demo@example.com' });
             return true;
         }
         return false;
    };

    if (typeof window !== 'undefined') {
        window.addEventListener('auth_state_change', checkMock);
        setTimeout(checkMock, 0);
    }

    return () => {
        if (typeof window !== 'undefined') window.removeEventListener('auth_state_change', checkMock);
    };
};

export const sendPasswordReset = async (email: string) => {
    if (!isMock) await auth.sendPasswordResetEmail(email);
};

export const exchangeThreadsAuth = async (code: string, redirectUri: string) => {
    // 商業化修正：必須通過後端交換，絕對不暴露 app_secret
    const res = await fetch('/api/threads', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ action: 'exchange', code, redirectUri })
    });

    const data = await res.json();
    if (!data.success) throw new Error(data.error || 'Threads 授權交換失敗');
    return data.data;
};

