    setLoadingAction(true);
    try {
        const key = await generateAdminKey(currentUser.user_id, type, role);
        setGeneratedKey(key);
        loadAllData();
    } catch (e: any) {
        alert(`生成失敗: ${e.message}`);
    } finally {
        setLoadingAction(false);
    }
