### 🔨 請手動更新 Firebase Rules (最終完整版)

上面的程式碼修復能讓功能「不會壞掉」，但為了讓排隊功能（避免多人同時使用導致 API 爆量）正常運作，請到 Firebase Console 更新 Rules：

```javascript
rules_version = '2';
service cloud.firestore {
  match /databases/{database}/documents {

    function isAdmin() {
      return request.auth != null && 
             get(/databases/$(database)/documents/users/$(request.auth.uid)).data.role == 'admin';
    }
    function isOwner(userId) {
      return request.auth != null && request.auth.uid == userId;
    }

    // 1. Users
    match /users/{userId} {
      allow read: if isOwner(userId) || isAdmin();
      allow write: if isOwner(userId) || isAdmin();
      match /{document=**} { allow read, write: if isOwner(userId) || isAdmin(); }
    }

    // 2. Admin Keys
    match /admin_keys/{keyId} {
      allow read, write: if request.auth != null;
    }

    // 3. System Stats (允許用戶寫入以統計 API 用量)
    match /system_stats/{docId} {
      allow read: if isAdmin();
      allow write: if request.auth != null; 
    }

    // 4. System Config
    match /system_config/{docId} {
       allow read: if request.auth != null;
       allow write: if isAdmin();
    }

    // 5. Usage Logs
    match /usage_logs/{docId} {
       allow create: if request.auth != null;
       allow read, delete: if isAdmin();
    }

    // 6. User Reports
    match /user_reports/{docId} {
       allow create: if request.auth != null;
       allow read, update: if isAdmin();
    }

    // 7. Quota Transactions
    match /quota_transactions/{docId} {
       allow read: if request.auth != null && request.auth.uid == resource.data.userId || isAdmin();
       allow create: if request.auth != null;
    }

    // 8. Brand Settings
    match /brand_settings/{userId} {
       allow read, write: if isOwner(userId) || isAdmin();
    }

    // 9. API Queue (排隊系統) - 新增
    match /api_queue/{docId} {
       allow read, create: if request.auth != null;
       allow update, delete: if request.auth != null; 
    }

    // 10. System Cache (快取) - 新增
    match /system_cache/{docId} {
       allow read, write: if request.auth != null;
    }
  }
}

關於您的疑問：**Firebase 免費版 (Spark Plan) 完全支援設定這些權限規則 (Rules)**。您不需要升級付費方案就能修改 Rules。

這個錯誤 `Missing or insufficient permissions` 是因為您的程式碼新增了「排隊機制」和「快取機制」，但資料庫規則還沒開放這兩個新區域的寫入權限。

### 1. 請前往 Firebase Console 修改 Rules

請複製以下完整的規則，並覆蓋您目前的設定。這組規則開放了 `api_queue` (排隊) 與 `system_cache` (快取) 的權限：

```javascript
rules_version = '2';
service cloud.firestore {
  match /databases/{database}/documents {

    // --- 輔助函式 ---
    function isAdmin() {
      return request.auth != null && 
             get(/databases/$(database)/documents/users/$(request.auth.uid)).data.role == 'admin';
    }

    function isOwner(userId) {
      return request.auth != null && request.auth.uid == userId;
    }

    // --- 既有規則 ---
    match /users/{userId} {
      allow read, write: if isOwner(userId) || isAdmin();
      match /{document=**} { allow read, write: if isOwner(userId) || isAdmin(); }
    }

    match /admin_keys/{keyId} {
      allow read, write: if request.auth != null;
    }

    match /system_stats/{docId} {
      allow read: if isAdmin();
      allow write: if request.auth != null; 
    }

    match /system_config/{docId} {
       allow read: if request.auth != null;
       allow write: if isAdmin();
    }

    match /usage_logs/{docId} {
       allow create: if request.auth != null;
       allow read, delete: if isAdmin();
    }

    match /user_reports/{docId} {
       allow create: if request.auth != null;
       allow read, update: if isAdmin();
    }

    match /quota_transactions/{docId} {
       allow read: if request.auth != null && request.auth.uid == resource.data.userId || isAdmin();
       allow create: if request.auth != null;
    }

    match /brand_settings/{userId} {
       allow read, write: if isOwner(userId) || isAdmin();
    }

    // --- 🟢 新增規則 (解決錯誤的關鍵) ---

    // 9. API Queue (排隊系統)：允許登入用戶寫入排隊請求
    match /api_queue/{docId} {
       allow read, write: if request.auth != null; 
    }

    // 10. System Cache (系統快取)：允許讀寫快取以節省 API 用量
    match /system_cache/{docId} {
       allow read, write: if request.auth != null;
    }
  }
}
```

### 2. 程式碼防護更新

為了避免您在修改 Rules 之前網站完全無法使用，我幫您更新 `services/queueService.ts`。
**更新後的效果：** 如果資料庫權限不足，系統會**自動跳過排隊機制**直接執行搜尋，這樣您的功能就不會報錯卡死了。

