export const findThreadsOpportunities = async (keyword: string): Promise<OpportunityPost[]> => {
    // 1. Construct Targeted Query
    // - site:threads.net/*/post: Forces it to find specific post pages (not profiles).
    // - when:1m: Restricts to the last month.
    // - Negatives: Exclude sales/promo terms.
    const searchQuery = `site:threads.net/*/post "${keyword}" (請問 OR 請益 OR 求救 OR 苦惱 OR 覺得 OR 難用 OR 怎麼辦) -開箱 -團購 -優惠 -折扣 -下單 -蝦皮 -賣場 -代購 -廣告 when:1m`;

    try {
        // Upgrade: Use gemini-3-pro-preview for better reasoning and search capabilities
        const response = await callBackend('generateContent', {
            model: 'gemini-3-pro-preview', 
            contents: `
                Role: Social Media Lead Scout (Taiwan Region).
                Task: Find potential customers on Threads who have a specific PROBLEM or QUESTION about: "${keyword}".

                [Search Query]: ${searchQuery}

                [STRICT FILTERING RULES]
                1. ❌ DISCARD: Posts that are clearly advertisements, product unboxings (unless criticizing), group buys (團購), or news sharing.
                2. ✅ KEEP: Real humans expressing frustration, asking for advice, or comparing products.
                3. 🌍 LOCATION: Must appear to be Taiwan context (Traditional Chinese).
                4. 📅 TIMEFRAME: Must be recent (within 1 month).

                [URL Extraction Rules]
                - You MUST extract the exact post URL from the search result.
                - It MUST match the pattern: https://www.threads.net/@username/post/code
                - Do NOT use google redirect links or search page links.

                [Output Format]
                RETURN ONLY A RAW JSON ARRAY. 
                Example:
                [
                    {
                        "content": "Full post text...",
                        "url": "https://www.threads.net/@user/post/123xyz",
                        "intentScore": 9,
                        "replyCount": "12", 
                        "likeCount": "50"
                    }
                ]

                If reply/like counts are not visible, set them to null. Do NOT invent numbers.
            `,
            config: { 
                tools: [{ googleSearch: {} }],
            }
        });

        const rawText = cleanJsonText(response.text || '[]');
        let raw;
        try {
            raw = JSON.parse(rawText);
        } catch (parseError) {
            console.error("Failed to parse Opportunity JSON:", rawText);
            throw new Error("AI 回傳格式錯誤，請重試");
        }

        if (!Array.isArray(raw)) return [];

        // Post-processing to ensure URLs are valid threads links
        const validResults = raw.filter((item: OpportunityPost) => {
            const hasValidUrl = item.url && item.url.includes('threads.net') && item.url.includes('/post/');
            // Filter out very low intent items if any slipped through
            const hasScore = (item.intentScore || 0) >= 3;
            return hasValidUrl && hasScore;
        });

        return validResults;

    } catch (e: any) {
        console.error("Opportunity search failed", e);
        throw new Error(`搜尋失敗: ${e.message}`);
    }
};

import React, { useState } from 'react';
import { OpportunityPost, ThreadsAccount, UserProfile } from '../../types';
import { findThreadsOpportunities } from '../../services/geminiService';
import { checkAndUseQuota } from '../../services/authService';
import { generateCommentReply } from '../../services/geminiService';
import { publishThreadsPost } from '../../services/threadsService';

interface Props {
    accounts: ThreadsAccount[];
    user: UserProfile | null;
    onQuotaUpdate: () => void;
}

const OpportunityScout: React.FC<Props> = ({ accounts, user, onQuotaUpdate }) => {
    const [keyword, setKeyword] = useState('');
    const [results, setResults] = useState<OpportunityPost[]>([]);
    const [isSearching, setIsSearching] = useState(false);
    const [selectedReplyId, setSelectedReplyId] = useState<string | null>(null);
    const [replyDraft, setReplyDraft] = useState('');
    const [isGeneratingReply, setIsGeneratingReply] = useState(false);
    const [replyAccountId, setReplyAccountId] = useState(accounts[0]?.id || '');

    // IME Composition State
    const [isComposing, setIsComposing] = useState(false);

    const handleSearch = async () => {
        if (!keyword.trim()) return alert("請輸入關鍵字");
        if (!user) return alert("請先登入");

        // Permission Check: Pro, Business, Admin only
        if (!['pro', 'business', 'admin'].includes(user.role)) {
            alert("🔒 此功能僅限 Pro 專業版以上會員使用。\n\n升級後即可無限次使用商機偵測功能！");
            return;
        }

        const COST = 0; // Free for Pro users
        const allowed = await checkAndUseQuota(user.user_id, COST, 'OPPORTUNITY_SEARCH');
        if (!allowed) return;
        onQuotaUpdate();

        setIsSearching(true);
        setResults([]);

        try {
            const leads = await findThreadsOpportunities(keyword);
            if (leads.length === 0) {
                alert("AI 搜尋完畢，但未發現合適的商機。\n\n可能原因：\n1. 該關鍵字最近 (1個月內) 沒有人提問。\n2. 搜尋結果多為廣告文，已被系統自動過濾。\n\n建議：嘗試更生活化的關鍵字，例如「好用嗎」、「求推薦」。");
            }
            setResults(leads);
        } catch (e: any) {
            alert(`搜尋失敗: ${e.message}`);
        } finally {
            setIsSearching(false);
        }
    };

    const handleGenerateReply = async (post: OpportunityPost, index: number) => {
        const account = accounts.find(a => a.id === replyAccountId);
        if (!account) return alert("請先選擇用來回覆的帳號");

        setSelectedReplyId(index.toString());
        setIsGeneratingReply(true);
        setReplyDraft('');

        try {
            const persona = account.styleGuide || account.personaPrompt || "Professional and helpful.";
            const replies = await generateCommentReply(post.content, persona);
            if (replies.length > 0) {
                setReplyDraft(replies[0]);
            } else {
                setReplyDraft("AI 無法生成建議，請手動撰寫。");
            }
        } catch (e) {
            setReplyDraft("生成失敗，請重試。");
        } finally {
            setIsGeneratingReply(false);
        }
    };

    const handleSendReply = async (post: OpportunityPost) => {
        const match = post.url.match(/\/post\/([a-zA-Z0-9_-]+)/);
        const threadId = match ? match[1] : null;

        if (!threadId) {
            alert("無法解析貼文 ID，請點擊「前往貼文」手動回覆。");
            window.open(post.url, '_blank');
            return;
        }

        const account = accounts.find(a => a.id === replyAccountId);
        if (!account) return;

        if (!confirm(`確定使用帳號 ${account.username} 發送回覆嗎？`)) return;

        try {
            const res = await publishThreadsPost(account, replyDraft, undefined, threadId);

            if (res.success) {
                alert("回覆發送成功！");
                setResults(prev => prev.filter(p => p !== post)); // Remove from list
                setSelectedReplyId(null);
            } else {
                console.warn("API Reply Error", res.error);
                if (res.error?.includes("Unsupported post request") || res.error?.includes("permission")) {
                    alert("⚠️ Threads API 限制：無法透過第三方工具直接回覆此貼文 (對方可能設定了隱私權限)。\n\n請點擊「前往貼文」手動操作，並貼上已複製的文案。");
                    navigator.clipboard.writeText(replyDraft);
                    window.open(post.url, '_blank');
                } else {
                    alert(`發送失敗: ${res.error}`);
                }
            }
        } catch (e: any) {
            alert(`錯誤: ${e.message}`);
        }
    };

    return (
        <div className="space-y-6">
            {/* Search Section */}
            <div className="bg-card p-6 rounded-xl border border-gray-700">
                <div className="flex flex-col md:flex-row gap-4 items-end">
                    <div className="flex-1 w-full">
                        <label className="block text-sm font-bold text-yellow-400 mb-2 uppercase tracking-wider">
                            商機關鍵字 (Intent Search)
                        </label>
                        <input 
                            value={keyword}
                            onChange={e => setKeyword(e.target.value)}
                            onCompositionStart={() => setIsComposing(true)}
                            onCompositionEnd={() => setIsComposing(false)}
                            placeholder="例如：過年禮盒、保濕精華液... (自動搜尋最近1個月)"
                            className="w-full bg-dark border border-gray-600 rounded-xl p-4 text-white placeholder-gray-500 focus:border-yellow-500 outline-none transition-colors"
                            onKeyDown={e => {
                                if (e.key === 'Enter' && !isComposing) {
                                    handleSearch();
                                }
                            }}
                        />
                    </div>
                    <button 
                        onClick={handleSearch} 
                        disabled={isSearching}
                        className="bg-yellow-600 hover:bg-yellow-500 text-black px-8 py-4 rounded-xl font-black shadow-lg transition-all w-full md:w-auto disabled:opacity-50 flex items-center justify-center gap-2 whitespace-nowrap"
                    >
                        {isSearching ? <div className="loader border-t-black"></div> : '商機開發 (Pro限定)'}
                    </button>
                </div>
                <p className="text-xs text-gray-500 mt-3 ml-1">
                    AI 智能過濾：系統自動鎖定<b>台灣地區</b>、<b>近一個月</b>貼文，並排除「開箱文」、「廣告文」，只鎖定「提問」、「求推薦」等具備強烈購買意圖的貼文。
                </p>
            </div>

            {/* Results Grid */}
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                {results.map((post, index) => (
