        if (match && match[1] && isValidNewsImage(match[1])) imageUrl = match[1];
    }
    if (imageUrl && (imageUrl.includes('googleusercontent.com') || imageUrl.includes('ggpht.com'))) {
        imageUrl = imageUrl.replace(/=[wh]\d+[-a-z0-9]*/, '=w800') + (imageUrl.match(/=[wh]\d+/) ? '' : '=w800');
    }
    return imageUrl;
};

const fetchRssContent = async (targetUrl: string): Promise<string> => {
    const data = await callBackend('fetchRss', { url: targetUrl });
    if (!data.text) throw new Error("Backend returned empty RSS content");
    return data.text;
};

const fetchRealtimeRss = async (keyword: string): Promise<TrendingTopic[]> => {
    // Fix: Force 'Taiwan' in query to prevent IP-based localization (US Server -> HK/Global Chinese results)
    const queryTerm = keyword.includes('台灣') || keyword.includes('Taiwan') ? keyword : `${keyword} 台灣`;

    // Construct Google News URL with explicit Taiwan bias
    const rssUrl = `https://news.google.com/rss/search?q=${encodeURIComponent(queryTerm)}+when:2d&hl=zh-TW&gl=TW&ceid=TW:zh-Hant`;

    try {
        const xmlString = await fetchRssContent(rssUrl);
        const parser = new DOMParser();
        const xml = parser.parseFromString(xmlString, "text/xml");
        const items = xml.querySelectorAll("item");
        const results: TrendingTopic[] = [];

        for (let i = 0; i < Math.min(items.length, 20); i++) {
            const item = items[i];
            const title = item.querySelector("title")?.textContent || "";
            const link = item.querySelector("link")?.textContent || "";
            const imageUrl = extractImageUrlFromItem(item);
            if (title && link) results.push({ title, description: title, url: link, imageUrl });
        }
        return results;
    } catch (e) { return []; }
};

export const fetchNewsImageFromUrl = async (url: string): Promise<string | null> => {
    if (!url) return null;
    try {
        const data = await callBackend('fetchOgImage', { url });
        if (data.imageUrl && isValidNewsImage(data.imageUrl)) return data.imageUrl;
    } catch (e) { console.warn("Backend OG fetch failed", e); }
    return null;
};

export const getTrendingTopics = async (industry: string = "台灣熱門時事", requestedCount: number = 10): Promise<TrendingTopic[]> => {
  const today = new Date().toISOString().split('T')[0];
  const cacheKey = `trend_search_${industry.replace(/\s+/g, '_')}_${today}`;

  // 1. Try Cache
  const cachedTopics = await getSystemCache(cacheKey);
  if (cachedTopics && Array.isArray(cachedTopics) && cachedTopics.length > 0) {
      return shuffleArray(cachedTopics).slice(0, requestedCount);
  }

  console.log(`[Cache] Miss: ${cacheKey}. Fetching live...`);

  // 2. Fetch Live (RSS + AI)
  let fetchedTopics: TrendingTopic[] = await fetchRealtimeRss(industry);

  // AI Supplement if RSS is weak
  if (fetchedTopics.length < 5) {
      try {
        const response = await callBackend('generateContent', {
            model: 'gemini-2.5-flash',
            contents: `Role: Trend Hunter. Generate 5 trending topics about "${industry}" in Taiwan (Traditional Chinese). Output Pure JSON Array: [{ "title": "...", "description": "...", "url": "#" }]`,
            config: { responseMimeType: "application/json" }
        });
        const raw = JSON.parse(cleanJsonText(response.text || '[]'));
        if (Array.isArray(raw)) {
            const aiTopics = raw.map((t: any) => ({ title: t.title, description: t.description || t.title, url: t.url || '#', imageUrl: undefined }));
            fetchedTopics = [...fetchedTopics, ...aiTopics];
        }
      } catch (e) { console.error("Gemini bypass generation failed", e); }
  }

  const uniqueTopics = Array.from(new Map(fetchedTopics.map(item => [item.title, item])).values());

  // 3. Save Cache
  if (uniqueTopics.length > 0) {
      await setSystemCache(cacheKey, uniqueTopics);
  }

  return shuffleArray(uniqueTopics).slice(0, requestedCount);
};

// --- URL Cleaner Helper ---
const generateShortThreadsUrl = (dirtyUrl: string, contentFallback: string): string => {
    try {
        // 1. Decode URL if it contains encoded parts
        let url = decodeURIComponent(dirtyUrl);

        // 2. Handle Google Redirects
        if (url.includes('google.com/url') || url.includes('googleusercontent')) {
            const params = new URLSearchParams(new URL(url).search);
            if (params.get('q')) url = params.get('q')!;
            else if (params.get('url')) url = params.get('url')!;
        }

        // 3. Extract Canonical Threads URL (Strict Pattern)
        // Matches: threads.net/@{username}/post/{postID}
        const match = url.match(/threads\.net\/@([a-zA-Z0-9_.-]+)\/post\/([a-zA-Z0-9_-]+)/);

        if (match) {
            // Reconstruct perfectly clean URL: https://www.threads.net/@user/post/id
            return `https://www.threads.net/@${match[1]}/post/${match[2]}`;
        }

        // 4. Fallback: If no valid Threads ID found, return a search URL
        // This handles "404" or "grounding-api-redirect" relative links
        const searchTerm = contentFallback.substring(0, 50).replace(/[^\w\s\u4e00-\u9fa5]/g, ' ').trim();
        return `https://www.threads.net/search?q=${encodeURIComponent(searchTerm)}`;

    } catch (e) {
        // Fallback on error
        const searchTerm = contentFallback.substring(0, 50).replace(/[^\w\s\u4e00-\u9fa5]/g, ' ').trim();
        return `https://www.threads.net/search?q=${encodeURIComponent(searchTerm)}`;
    }
};

// NEW: Business Opportunity Search (Markdown Parsing Strategy)
export const findThreadsOpportunities = async (keyword: string): Promise<OpportunityPost[]> => {
    // Query Optimization: Use broader query to ensure results.
    const searchQuery = `Threads "${keyword}"`; 

    try {
        const response = await callBackend('generateContent', {
            model: 'gemini-2.5-flash', 
            contents: `
                Role: Social Media Researcher.
                Task: Search for user posts on Threads related to: ${keyword}

                [Tool Instruction]
                Use the Google Search tool with the query: '${searchQuery}'

                [Output Rules]
                1. Find at least 10 distinct discussions or posts.
                2. Extract the snippet and URL if available.
                3. **CRITICAL**: If the URL looks like a redirect or you are unsure, just provide it anyway. Do not filter results just because the link is imperfect.
                4. **FORMAT STRICTLY** using the block format below for each post found.

                BLOCK_START
                CONTENT: [Summary of what the user posted]
                LINK: [URL of the post]
                SCORE: [1-10 (Intent Score)]
                REPLY_COUNT: [Number or N/A]
                LIKE_COUNT: [Number or N/A]
                BLOCK_END

                (Repeat the block for each post found, ideally 10-15 times)
            `,
            config: { 
                tools: [{ googleSearch: {} }],
                safetySettings: [
                    { category: 'HARM_CATEGORY_HARASSMENT', threshold: 'BLOCK_NONE' },
                    { category: 'HARM_CATEGORY_HATE_SPEECH', threshold: 'BLOCK_NONE' },
                    { category: 'HARM_CATEGORY_SEXUALLY_EXPLICIT', threshold: 'BLOCK_NONE' },
                    { category: 'HARM_CATEGORY_DANGEROUS_CONTENT', threshold: 'BLOCK_NONE' }
                ]
            }
        });

        const rawText = response.text || '';
        console.log("🔍 Raw Threads Result (Markdown):", rawText.substring(0, 200) + "..."); 

        // Parse the Custom Block Format
        const results: OpportunityPost[] = [];
        const blocks = rawText.split('BLOCK_START');

        for (const block of blocks) {
            if (!block.includes('BLOCK_END')) continue;

            const contentMatch = block.match(/CONTENT:\s*(.+)/);
            const linkMatch = block.match(/LINK:\s*(.+)/);
            const scoreMatch = block.match(/SCORE:\s*(\d+)/);
            const replyMatch = block.match(/REPLY_COUNT:\s*(.+)/);
            const likeMatch = block.match(/LIKE_COUNT:\s*(.+)/);

            if (contentMatch) {
                const content = contentMatch[1].trim();
                let rawUrl = linkMatch ? linkMatch[1].trim() : '';

                // Smart Cleaning: Convert whatever AI found into a working Threads Link
                const cleanUrl = generateShortThreadsUrl(rawUrl, content);

                results.push({
                    content: content,
                    url: cleanUrl, // Guaranteed to be a valid URL (Direct or Search)
                    reasoning: '',
                    intentScore: scoreMatch ? parseInt(scoreMatch[1]) : 5,
                    replyCount: replyMatch ? replyMatch[1].trim() : undefined,
                    likeCount: likeMatch ? likeMatch[1].trim() : undefined
                });
            }
        }

        // Limit results to 10 max as requested
        return results.slice(0, 10);

    } catch (e: any) {
        console.error("Opportunity search failed", e);
        return []; 
    }
};

import React, { useState } from 'react';
import { OpportunityPost, ThreadsAccount, UserProfile } from '../../types';
import { findThreadsOpportunities } from '../../services/geminiService';
import { checkAndUseQuota } from '../../services/authService';
import { generateCommentReply } from '../../services/geminiService';
import { publishThreadsPost } from '../../services/threadsService';

interface Props {
    accounts: ThreadsAccount[];
    user: UserProfile | null;
    onQuotaUpdate: () => void;
}

const OpportunityScout: React.FC<Props> = ({ accounts, user, onQuotaUpdate }) => {
    const [keyword, setKeyword] = useState('');
    const [results, setResults] = useState<OpportunityPost[]>([]);
    const [isSearching, setIsSearching] = useState(false);
    const [selectedReplyId, setSelectedReplyId] = useState<string | null>(null);
    const [replyDraft, setReplyDraft] = useState('');
    const [isGeneratingReply, setIsGeneratingReply] = useState(false);
    const [replyAccountId, setReplyAccountId] = useState(accounts[0]?.id || '');

    // IME Composition State
    const [isComposing, setIsComposing] = useState(false);

    const handleSearch = async () => {
        if (!keyword.trim()) return alert("請輸入關鍵字");
        if (!user) return alert("請先登入");

        // Permission Check: Pro, Business, Admin only
        if (!['pro', 'business', 'admin'].includes(user.role)) {
            alert("🔒 此功能僅限 Pro 專業版以上會員使用。\n\n升級後即可無限次使用商機偵測功能！");
            return;
        }

        const COST = 0; // Free for Pro users
        const allowed = await checkAndUseQuota(user.user_id, COST, 'OPPORTUNITY_SEARCH');
        if (!allowed) return;
        onQuotaUpdate();

        setIsSearching(true);
        setResults([]);

        try {
            const leads = await findThreadsOpportunities(keyword);
            if (leads.length === 0) {
                alert("AI 搜尋完畢，但未發現合適的商機。\n\n可能原因：\n1. 該關鍵字最近 (1個月內) 沒有人提問。\n2. 搜尋結果多為廣告文，已被系統自動過濾。\n\n建議：嘗試更生活化的關鍵字，例如「好用嗎」、「求推薦」。");
            }
            setResults(leads);
        } catch (e: any) {
            alert(`搜尋失敗: ${e.message}`);
        } finally {
            setIsSearching(false);
        }
    };

    const handleGenerateReply = async (post: OpportunityPost, index: number) => {
        const account = accounts.find(a => a.id === replyAccountId);
        if (!account) return alert("請先選擇用來回覆的帳號");

        setSelectedReplyId(index.toString());
        setIsGeneratingReply(true);
        setReplyDraft('');

        try {
            const persona = account.styleGuide || account.personaPrompt || "Professional and helpful.";
            const replies = await generateCommentReply(post.content, persona);
            if (replies.length > 0) {
                setReplyDraft(replies[0]);
            } else {
                setReplyDraft("AI 無法生成建議，請手動撰寫。");
            }
        } catch (e) {
            setReplyDraft("生成失敗，請重試。");
        } finally {
            setIsGeneratingReply(false);
        }
    };

    const handleSendReply = async (post: OpportunityPost) => {
        const match = post.url.match(/\/post\/([a-zA-Z0-9_-]+)/);
        const threadId = match ? match[1] : null;

        if (!threadId) {
            alert("無法解析貼文 ID，請點擊「前往貼文」手動回覆。");
            window.open(post.url, '_blank');
            return;
        }

        const account = accounts.find(a => a.id === replyAccountId);
        if (!account) return;

        if (!confirm(`確定使用帳號 ${account.username} 發送回覆嗎？`)) return;

        try {
            const res = await publishThreadsPost(account, replyDraft, undefined, threadId);

            if (res.success) {
                alert("回覆發送成功！");
                setResults(prev => prev.filter(p => p !== post)); // Remove from list
                setSelectedReplyId(null);
            } else {
                console.warn("API Reply Error", res.error);
                if (res.error?.includes("Unsupported post request") || res.error?.includes("permission")) {
                    alert("⚠️ Threads API 限制：無法透過第三方工具直接回覆此貼文 (對方可能設定了隱私權限)。\n\n請點擊「前往貼文」手動操作，並貼上已複製的文案。");
                    navigator.clipboard.writeText(replyDraft);
                    window.open(post.url, '_blank');
                } else {
                    alert(`發送失敗: ${res.error}`);
                }
            }
        } catch (e: any) {
            alert(`錯誤: ${e.message}`);
        }
    };

    // Helper: Determine if the URL is a direct link or a search fallback
    const isSearchFallback = (url: string) => url.includes('/search?q=');

    return (
        <div className="space-y-6">
            {/* Search Section */}
            <div className="bg-card p-6 rounded-xl border border-gray-700">
                <div className="flex flex-col md:flex-row gap-4 items-end">
                    <div className="flex-1 w-full">
                        <label className="block text-sm font-bold text-yellow-400 mb-2 uppercase tracking-wider">
                            商機關鍵字 (Intent Search)
                        </label>
                        <input 
                            value={keyword}
                            onChange={e => setKeyword(e.target.value)}
                            onCompositionStart={() => setIsComposing(true)}
                            onCompositionEnd={() => setIsComposing(false)}
                            placeholder="例如：過年禮盒、保濕精華液... (自動搜尋最近1個月)"
                            className="w-full bg-dark border border-gray-600 rounded-xl p-4 text-white placeholder-gray-500 focus:border-yellow-500 outline-none transition-colors"
                            onKeyDown={e => {
                                if (e.key === 'Enter' && !isComposing) {
                                    handleSearch();
                                }
                            }}
                        />
                    </div>
                    <button 
                        onClick={handleSearch} 
                        disabled={isSearching}
                        className="bg-yellow-600 hover:bg-yellow-500 text-black px-8 py-4 rounded-xl font-black shadow-lg transition-all w-full md:w-auto disabled:opacity-50 flex items-center justify-center gap-2 whitespace-nowrap"
                    >
                        {isSearching ? <div className="loader border-t-black"></div> : '商機開發 (Pro限定)'}
                    </button>
                </div>
                <p className="text-xs text-gray-500 mt-3 ml-1">
                    AI 智能過濾：系統自動鎖定<b>台灣地區</b>、<b>近一個月</b>貼文，並排除「開箱文」、「廣告文」，只鎖定「提問」、「求推薦」等具備強烈購買意圖的貼文。
                </p>
            </div>

            {/* Results Grid */}
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                {results.map((post, index) => (
                    <div key={index} className="bg-gradient-to-br from-gray-900 to-black p-6 rounded-2xl border border-gray-800 hover:border-yellow-500/50 transition-all group relative flex flex-col h-full">
                        {/* Intent Score Badge */}
                        <div className="absolute top-4 right-4 flex items-center gap-1 bg-yellow-900/30 text-yellow-400 px-2 py-1 rounded text-xs font-bold border border-yellow-500/20">
                            <span>🔥 意圖: {post.intentScore}/10</span>
                        </div>

                        {/* Content */}
                        <div className="mb-4 pr-16 flex-1">
                            <p className="text-gray-300 text-sm leading-relaxed line-clamp-4 font-medium">"{post.content}"</p>
                        </div>

                        {/* Metrics Bar (Hidden if data is invalid/null) */}
                        {(post.replyCount && post.replyCount !== 'null' && post.replyCount !== '0' && post.likeCount && post.likeCount !== 'null' && post.likeCount !== '0') && (
                            <div className="flex items-center gap-4 text-xs text-gray-500 mb-4 px-1">
                                <span className="flex items-center gap-1" title="留言數 (估計)">
                                    💬 <span className="font-mono text-gray-300">{post.replyCount}</span>
                                </span>
                                <span className="flex items-center gap-1" title="按讚數 (估計)">
                                    ❤️ <span className="font-mono text-gray-300">{post.likeCount}</span>
                                </span>
                            </div>
                        )}

                        {/* Action Area */}
                        {selectedReplyId === index.toString() ? (
                            <div className="animate-fade-in mt-auto bg-gray-800 p-4 rounded-xl border border-gray-600">
                                <div className="flex justify-between items-center mb-2">
                                    <label className="text-xs text-gray-400 font-bold">擬稿中...</label>
                                    <button onClick={() => setSelectedReplyId(null)} className="text-gray-500 hover:text-white">✕</button>
                                </div>
                                <textarea 
                                    value={replyDraft}
                                    onChange={e => setReplyDraft(e.target.value)}
                                    className="w-full h-24 bg-black/50 border border-gray-600 rounded p-2 text-sm text-white mb-2 resize-none focus:border-yellow-500 outline-none"
                                    placeholder={isGeneratingReply ? "AI 正在撰寫中..." : "在此編輯回覆..."}
                                />
                                <div className="flex gap-2">
                                    <button 
                                        onClick={() => handleSendReply(post)}
                                        disabled={isGeneratingReply || !replyDraft}
                                        className="w-full bg-yellow-600 hover:bg-yellow-500 text-black font-bold py-2 rounded transition-colors disabled:opacity-50 text-xs"
                                    >
                                        🚀 發送回覆 (API)
                                    </button>
                                </div>
                            </div>
                        ) : (
                            <div className="flex flex-col gap-3 mt-auto pt-4 border-t border-gray-800">
                                <div className="flex gap-2">
                                    <select 
                                        value={replyAccountId} 
                                        onChange={e => setReplyAccountId(e.target.value)}
                                        className="bg-black border border-gray-700 rounded px-2 text-xs text-white outline-none flex-1 py-2"
                                    >
                                        {accounts.map(acc => <option key={acc.id} value={acc.id}>{acc.username}</option>)}
                                    </select>
                                    <button 
                                        onClick={() => handleGenerateReply(post, index)}
                                        className="flex-1 bg-white text-black font-bold py-2 rounded text-xs hover:bg-gray-200 transition-colors border border-transparent"
                                    >
                                        ✍️ AI 擬稿
                                    </button>
                                </div>

                                <a 
                                    href={post.url} 
                                    target="_blank" 
                                    rel="noreferrer"
                                    className="w-full bg-gray-800 hover:bg-gray-700 text-white font-bold py-3 rounded-lg transition-all flex items-center justify-center gap-2 border border-gray-600 hover:border-white/50 group text-xs"
                                >
                                    <span>↗</span> {isSearchFallback(post.url) ? '找不到直連，前往搜尋' : '前往貼文 (Short URL)'}
                                </a>
                            </div>
                        )}
                    </div>
                ))}
            </div>

            {!isSearching && results.length === 0 && keyword && (
                <div className="text-center py-20 text-gray-500">
                    輸入關鍵字並點擊「商機開發」開始搜尋。
                </div>
            )}
        </div>
    );
};

