// --- URL Cleaner Helper (Aggressive) ---
const generateShortThreadsUrl = (dirtyUrl: string, contentFallback: string): string => {
    try {
        let url = dirtyUrl;

        // 1. Unwrap Google Redirects (google.com/url?q=REAL_URL&...)
        if (url.includes('google.com/url')) {
            const match = url.match(/[?&]q=([^&]+)/);
            if (match && match[1]) {
                url = decodeURIComponent(match[1]);
            }
        } else {
             // Sometimes it's double encoded
             url = decodeURIComponent(url);
        }

        // 2. Strict Pattern Extraction: threads.net/@{user}/post/{id}
        // Matches: threads.net followed by @username followed by /post/ followed by ID
        const match = url.match(/threads\.net\/@([^\/]+)\/post\/([a-zA-Z0-9_-]+)/);

        if (match) {
            // Found standard pattern! Reconstruct cleanly.
            return `https://www.threads.net/@${match[1]}/post/${match[2]}`;
        }

        // 3. Loose Pattern: If it contains threads.net and /post/, but maybe regex failed on username char?
        // Let's trust the input url but strip query params
        if (url.includes('threads.net') && url.includes('/post/')) {
             try {
                 const urlObj = new URL(url.startsWith('http') ? url : `https://${url}`);
                 // Return Origin + Path (strips ?igshid=... or utm)
                 return urlObj.origin + urlObj.pathname;
             } catch (e) {
                 // Invalid URL format, fall through
             }
        }

        // 4. Fallback: Search URL
        // Only used if we absolutely cannot find a direct link structure
        const searchTerm = contentFallback.substring(0, 50).replace(/[^\w\s\u4e00-\u9fa5]/g, ' ').trim();
        return `https://www.threads.net/search?q=${encodeURIComponent(searchTerm)}`;

    } catch (e) {
        // Safety net
        const searchTerm = contentFallback.substring(0, 50).replace(/[^\w\s\u4e00-\u9fa5]/g, ' ').trim();
        return `https://www.threads.net/search?q=${encodeURIComponent(searchTerm)}`;
    }
};

