        const enclosure = item.getElementsByTagName('enclosure')[0];
        if (enclosure && (enclosure.getAttribute('type') || '').startsWith('image')) imageUrl = enclosure.getAttribute('url') || '';
    }
    if (!imageUrl) {
        const descRaw = item.querySelector("description")?.textContent || "";
        const match = decodeHtml(descRaw).match(/<img[^>]+src=["']([^"']+)["']/i);
        if (match && match[1] && isValidNewsImage(match[1])) imageUrl = match[1];
    }
    if (imageUrl && (imageUrl.includes('googleusercontent.com') || imageUrl.includes('ggpht.com'))) {
        imageUrl = imageUrl.replace(/=[wh]\d+[-a-z0-9]*/, '=w800') + (imageUrl.match(/=[wh]\d+/) ? '' : '=w800');
    }
    return imageUrl;
};

const fetchRssContent = async (targetUrl: string): Promise<string> => {
    const data = await callBackend('fetchRss', { url: targetUrl });
    if (!data.text) throw new Error("Backend returned empty RSS content");
    return data.text;
};

const fetchRealtimeRss = async (keyword: string): Promise<TrendingTopic[]> => {
    // Fix: Force 'Taiwan' in query to prevent IP-based localization (US Server -> HK/Global Chinese results)
    const queryTerm = keyword.includes('台灣') || keyword.includes('Taiwan') ? keyword : `${keyword} 台灣`;

    // Construct Google News URL with explicit Taiwan bias
    const rssUrl = `https://news.google.com/rss/search?q=${encodeURIComponent(queryTerm)}+when:2d&hl=zh-TW&gl=TW&ceid=TW:zh-Hant`;

    try {
        const xmlString = await fetchRssContent(rssUrl);
        const parser = new DOMParser();
        const xml = parser.parseFromString(xmlString, "text/xml");
        const items = xml.querySelectorAll("item");
        const results: TrendingTopic[] = [];

        for (let i = 0; i < Math.min(items.length, 20); i++) {
            const item = items[i];
            const title = item.querySelector("title")?.textContent || "";
            const link = item.querySelector("link")?.textContent || "";
            const imageUrl = extractImageUrlFromItem(item);
            if (title && link) results.push({ title, description: title, url: link, imageUrl });
        }
        return results;
    } catch (e) { return []; }
};

export const fetchNewsImageFromUrl = async (url: string): Promise<string | null> => {
    if (!url) return null;
    try {
        const data = await callBackend('fetchOgImage', { url });
        if (data.imageUrl && isValidNewsImage(data.imageUrl)) return data.imageUrl;
    } catch (e) { console.warn("Backend OG fetch failed", e); }
    return null;
};

export const getTrendingTopics = async (industry: string = "台灣熱門時事", requestedCount: number = 10): Promise<TrendingTopic[]> => {
  const today = new Date().toISOString().split('T')[0];
  const cacheKey = `trend_search_${industry.replace(/\s+/g, '_')}_${today}`;

  // 1. Try Cache
  const cachedTopics = await getSystemCache(cacheKey);
  if (cachedTopics && Array.isArray(cachedTopics) && cachedTopics.length > 0) {
      return shuffleArray(cachedTopics).slice(0, requestedCount);
  }

  console.log(`[Cache] Miss: ${cacheKey}. Fetching live...`);

  // 2. Fetch Live (RSS + AI)
  let fetchedTopics: TrendingTopic[] = await fetchRealtimeRss(industry);

  // AI Supplement if RSS is weak
  if (fetchedTopics.length < 5) {
      try {
        const response = await callBackend('generateContent', {
            model: 'gemini-2.5-flash',
            contents: `Role: Trend Hunter. Generate 5 trending topics about "${industry}" in Taiwan (Traditional Chinese). Output Pure JSON Array: [{ "title": "...", "description": "...", "url": "#" }]`,
            config: { responseMimeType: "application/json" }
        });
        const raw = JSON.parse(cleanJsonText(response.text || '[]'));
        if (Array.isArray(raw)) {
            const aiTopics = raw.map((t: any) => ({ title: t.title, description: t.description || t.title, url: t.url || '#', imageUrl: undefined }));
            fetchedTopics = [...fetchedTopics, ...aiTopics];
        }
      } catch (e) { console.error("Gemini bypass generation failed", e); }
  }

  const uniqueTopics = Array.from(new Map(fetchedTopics.map(item => [item.title, item])).values());

  // 3. Save Cache
  if (uniqueTopics.length > 0) {
      await setSystemCache(cacheKey, uniqueTopics);
  }

  return shuffleArray(uniqueTopics).slice(0, requestedCount);
};

// --- Smart Link Logic ---
const extractThreadsId = (url: string): string | null => {
    if (!url) return null;
    try {
        const decoded = decodeURIComponent(url);
        const match = decoded.match(/\/post\/([a-zA-Z0-9_-]+)/);
        if (match && match[1]) {
            return match[1];
        }
    } catch (e) {}
    return null;
};

// Internal Helper for AI Execution
const executeOpportunitySearch = async (searchQuery: string, keyword: string): Promise<OpportunityPost[]> => {
    const intentList = ["推薦", "請益", "求救", "預算", "尋找", "真實", "口袋名單", "清單", "好用嗎"];

    try {
        const response = await callBackend('generateContent', {
            model: 'gemini-2.5-flash', 
            contents: `
                Goal: Find active buying/discussion opportunities on Threads about "${keyword}".

                [Tool Instruction]
                Perform a Google Search for: '${searchQuery}'

                [AI SEMANTIC FILTERING]
                You have search results. Now filter them.
                A result is a VALID OPPORTUNITY if:
                1. It is from Threads.net (or relevant discussion).
                2. It is relevant to "${keyword}".
                3. It implies a user question, discussion, or buying intent.

                [Output Requirement]
                - Extract up to 8 distinct posts.
                - **Language**: Summaries in Traditional Chinese.
                - **Intent Score**: 1-10 (10 = User is begging for a recommendation).

                Format each result strictly:
                BLOCK_START
                CONTENT: [Summary of the user's specific need]
                URL: [The full link]
                SCORE: [1-10]
                BLOCK_END
            `,
            config: { 
                tools: [{ googleSearch: {} }],
                safetySettings: [
                    { category: 'HARM_CATEGORY_HARASSMENT', threshold: 'BLOCK_NONE' },
                    { category: 'HARM_CATEGORY_HATE_SPEECH', threshold: 'BLOCK_NONE' },
                    { category: 'HARM_CATEGORY_SEXUALLY_EXPLICIT', threshold: 'BLOCK_NONE' },
                    { category: 'HARM_CATEGORY_DANGEROUS_CONTENT', threshold: 'BLOCK_NONE' }
                ]
            }
        });

        const rawText = response.text || '';
        console.log(`🔍 Search [${searchQuery}] Raw Length:`, rawText.length); 

        const results: OpportunityPost[] = [];
        const blocks = rawText.split(/BLOCK_START/i);

        for (const block of blocks) {
            if (!block.match(/BLOCK_END/i)) continue;

            const contentMatch = block.match(/CONTENT:\s*(.+)/i);
            const urlMatch = block.match(/URL:\s*(.+)/i);
            const scoreMatch = block.match(/SCORE:\s*(\d+)/i);

            if (contentMatch) {
                const content = contentMatch[1].trim();
                const rawUrl = urlMatch ? urlMatch[1].trim() : '';

                let finalUrl = '';
                const shortcode = extractThreadsId(rawUrl);

                if (shortcode) {
                    finalUrl = `https://www.threads.net/post/${shortcode}`;
                } else if (rawUrl.includes('threads.net')) {
                    finalUrl = rawUrl;
                } else {
                    const cleanQuery = content.substring(0, 40).replace(/[^\w\s\u4e00-\u9fa5]/g, ' ').trim();
                    finalUrl = `https://www.threads.net/search?q=${encodeURIComponent(cleanQuery)}`;
                }

                results.push({
                    content: content,
                    url: finalUrl,
                    reasoning: '',
                    intentScore: scoreMatch ? parseInt(scoreMatch[1]) : 5,
                    replyCount: '?',
                    likeCount: '?'
                });
            }
        }
        return results;
    } catch (e) {
        console.error("Execute search failed:", e);
        return [];
    }
};

export const findThreadsOpportunities = async (keyword: string): Promise<OpportunityPost[]> => {
    // --- Query Optimization Strategy (Multi-Stage Fallback) ---
    // Problem: Strict search (date + site) often returns 0 results due to indexing lag or bad date calculation.
    // Solution: Try strict -> Try moderate -> Try broad.

    // 1. Calculate Date (30 Days Ago) using Timestamp Math (Safer than setMonth)
    const thirtyDaysMs = 30 * 24 * 60 * 60 * 1000;
    const afterDate = new Date(Date.now() - thirtyDaysMs).toISOString().split('T')[0];

    // Stage 1: Strict (Site + Date)
    // "site:threads.net {keyword} after:YYYY-MM-DD"
    console.log("🚀 Opportunity Search Stage 1: Strict");
    let results = await executeOpportunitySearch(`site:threads.net ${keyword} after:${afterDate}`, keyword);

    if (results.length === 0) {
        // Stage 2: Moderate (Site only)
        // "site:threads.net {keyword}"
        console.log("⚠️ Stage 1 Empty. Retrying Stage 2: Moderate (No Date)...");
        results = await executeOpportunitySearch(`site:threads.net ${keyword}`, keyword);
    }

    if (results.length === 0) {
        // Stage 3: Broad (Keyword + "threads")
        // "{keyword} threads" -> Relies on Google's relevance matching
        console.log("⚠️ Stage 2 Empty. Retrying Stage 3: Broad (Keyword + Context)...");
        results = await executeOpportunitySearch(`${keyword} threads`, keyword);
    }

    return results.slice(0, 10);
};

module.exports = async function (req, res) {
  // CORS Headers
  res.setHeader('Access-Control-Allow-Credentials', true);
  res.setHeader('Access-Control-Allow-Origin', '*');
  res.setHeader('Access-Control-Allow-Methods', 'GET,OPTIONS,PATCH,DELETE,POST,PUT');
  res.setHeader(
    'Access-Control-Allow-Headers',
    'X-CSRF-Token, X-Requested-With, Accept, Accept-Version, Content-Length, Content-MD5, Content-Type, Date, X-Api-Version'
  );

  if (req.method === 'OPTIONS') {
    res.status(200).end();
    return;
  }

  if (req.method !== 'POST') {
    return res.status(405).json({ error: 'Method Not Allowed' });
  }

  if (!req.body) {
      return res.status(400).json({ error: 'Missing Request Body' });
  }

  // --- Key Manager & Load Balancing ---
  class KeyManager {
      constructor() {
          this.geminiKeys = [
              process.env.API_KEY,
              process.env.API_KEY_2,
              process.env.API_KEY_3,
              process.env.API_KEY_4,
              process.env.API_KEY_5
          ].filter(k => k && k.length > 10 && k !== 'undefined');

          this.openAIKey = process.env.OPENAI_API_KEY;

          this.ideogramKeys = [
              process.env.IDEOGRAM_API_KEY,
              process.env.IDEOGRAM_API_KEY_2
          ].filter(k => k && k.length > 0 && k !== 'undefined');

          this.grokKey = process.env.GROK_API_KEY;

          this.currentIndex = this.geminiKeys.length > 0 
              ? Math.floor(Math.random() * this.geminiKeys.length) 
              : 0;
      }

      getCurrentKey() {
          if (this.geminiKeys.length === 0) return null;
          return this.geminiKeys[this.currentIndex];
      }

      getCurrentKeySlotIndex() {
          return this.currentIndex + 1;
      }

      getIdeogramKey() {
          if (this.ideogramKeys.length === 0) return null;
          return this.ideogramKeys[Math.floor(Math.random() * this.ideogramKeys.length)];
      }

      getGrokKey() { return this.grokKey; }
      getOpenAIKey() { return this.openAIKey; }

      getKeyConfigStatus() {
          return {
              keyStatus: [
                  !!(process.env.API_KEY && process.env.API_KEY.length > 10),
                  !!(process.env.API_KEY_2 && process.env.API_KEY_2.length > 10),
                  !!(process.env.API_KEY_3 && process.env.API_KEY_3.length > 10),
                  !!(process.env.API_KEY_4 && process.env.API_KEY_4.length > 10),
                  !!(process.env.API_KEY_5 && process.env.API_KEY_5.length > 10)
              ],
              providers: {
                  openai: !!(process.env.OPENAI_API_KEY && process.env.OPENAI_API_KEY.length > 10),
                  ideogram: !!(process.env.IDEOGRAM_API_KEY),
                  grok: !!(process.env.GROK_API_KEY)
              }
          };
      }

      switchToNextKey() {
          if (this.geminiKeys.length > 1) {
              const oldIndex = this.currentIndex;
              this.currentIndex = (this.currentIndex + 1) % this.geminiKeys.length;
              console.warn(`[KeyManager] ⚠️ Key Slot ${oldIndex + 1} exhausted. Switching to Slot ${this.currentIndex + 1}...`);
              return true;
          }
          return false;
      }
  }

  const keyManager = new KeyManager();
  const delay = (ms) => new Promise(resolve => setTimeout(resolve, ms));

  const isRetryableError = (error) => {
      const msg = (error.message || '').toLowerCase();
      const status = error.status || error.response?.status;
      return (
          msg.includes('429') || status === 429 ||
          msg.includes('quota') || msg.includes('resource exhausted') || 
          msg.includes('limit') || msg.includes('overloaded') ||
          msg.includes('503') || status === 503
      );
  };

  async function executeWithRetry(operation) {
      if (keyManager.geminiKeys.length === 0) throw new Error("Server Error: No Gemini API Keys configured.");

      let lastError = null;
      const attempts = keyManager.geminiKeys.length;

      let GoogleGenAI;
      try {
          const sdk = await import("@google/genai");
          GoogleGenAI = sdk.GoogleGenAI;
      } catch (e) { throw new Error(`SDK Load Failed: ${e.message}`); }

      for (let i = 0; i < attempts; i++) {
          const currentKey = keyManager.getCurrentKey();
          const currentSlot = keyManager.getCurrentKeySlotIndex();

          try {
              const ai = new GoogleGenAI({ apiKey: currentKey });
              const result = await operation(ai, currentKey);
              return result;

          } catch (error) {
              lastError = error;

              if (isRetryableError(error)) {
                  console.warn(`[Gemini] Key Slot ${currentSlot} hit rate limit (429/Quota).`);
                  if (i < attempts - 1) {
                      keyManager.switchToNextKey();
                      await delay(300 + Math.random() * 500); 
                      continue; 
                  }
              }

              if (error.status === 400 && !error.message.toLowerCase().includes('key')) {
                  throw error; 
              }
          }
      }
      console.error("[Gemini] All API keys exhausted.");
      throw new Error(`All API keys exhausted. Last error: ${lastError?.message}`);
  }

  // --- Provider Implementations (STANDARD QUALITY ENFORCED) ---

  async function generateIdeogramImage(prompt) {
      const apiKey = keyManager.getIdeogramKey();
      if (!apiKey) return null; 

      // Ensure no high-res contamination
      const cleanPrompt = prompt.replace(/8k|highly detailed|masterpiece/gi, "").trim();
      const finalPrompt = `${cleanPrompt}, standard web quality, realistic social media photo`;

      let ar = "ASPECT_1_1";
      if (prompt.includes("16:9")) ar = "ASPECT_16_9";
      if (prompt.includes("9:16")) ar = "ASPECT_9_16";

      const response = await fetch("https://api.ideogram.ai/generate", {
          method: "POST",
          headers: { "Api-Key": apiKey, "Content-Type": "application/json" },
          // Using V_1 or V_2 depending on cost/speed preference for "Standard"
          body: JSON.stringify({ image_request: { prompt: finalPrompt, aspect_ratio: ar, model: "V_2", magic_prompt_option: "AUTO" } })
      });
      if (!response.ok) throw new Error(`Ideogram Error: ${response.status}`);
      const data = await response.json();
      const imageUrl = data.data?.[0]?.url;
      if (!imageUrl) throw new Error("Ideogram returned no image URL");
      const imgRes = await fetch(imageUrl);
      const arrayBuffer = await imgRes.arrayBuffer();
      return Buffer.from(arrayBuffer).toString('base64');
  }

  async function generateGrokImage(prompt) {
      const apiKey = keyManager.getGrokKey();
      if (!apiKey) return null;

      const cleanPrompt = prompt.replace(/8k|highly detailed|masterpiece/gi, "").trim();

      const response = await fetch("https://api.x.ai/v1/images/generations", {
          method: "POST",
          headers: { "Authorization": `Bearer ${apiKey}`, "Content-Type": "application/json" },
          // Grok only has one model currently, control via prompt
          body: JSON.stringify({ prompt: cleanPrompt, model: "grok-beta", n: 1, size: "1024x1024", response_format: "b64_json" })
      });
      if (!response.ok) throw new Error(`Grok Error`);
      const data = await response.json();
      return data.data?.[0]?.b64_json;
  }

  async function generateOpenAIImage(prompt) {
      const apiKey = keyManager.getOpenAIKey();
      if (!apiKey) return null;

      const cleanPrompt = prompt.replace(/8k|highly detailed|masterpiece/gi, "").trim();

      const response = await fetch("https://api.openai.com/v1/images/generations", {
          method: "POST",
          headers: { "Content-Type": "application/json", "Authorization": `Bearer ${apiKey}` },
          // Using standard quality explicitly
          body: JSON.stringify({ model: "dall-e-3", prompt: cleanPrompt, n: 1, size: "1024x1024", quality: "standard", response_format: "b64_json" })
      });
      const data = await response.json();
      if (data.error) throw new Error(`OpenAI Error: ${data.error.message}`);
      return data.data[0].b64_json;
  }

  try {
    const { action, payload } = req.body;
    if (!action) return res.status(400).json({ error: "Missing 'action'" });

    if (action === 'getServiceStatus') {
        const statusConfig = keyManager.getKeyConfigStatus();
        return res.status(200).json({ 
            keyStatus: statusConfig.keyStatus,
            providers: statusConfig.providers,
            totalConfigured: statusConfig.keyStatus.filter(s => s).length
        });
    }

    if (action === 'fetchRss') {
        const { url } = payload;
        const rssRes = await fetch(url);
        return res.status(200).json({ text: await rssRes.text() });
    }

    if (action === 'fetchOgImage') {
        const { url } = payload;
        const htmlRes = await fetch(url, { headers: { 'User-Agent': 'Bot' } });
        const html = await htmlRes.text();
        const match = html.match(/<meta[^>]+property=["']og:image["'][^>]+content=["']([^"']+)["']/i);
        return res.status(200).json({ imageUrl: match ? match[1] : null });
    }

    if (action === 'generateContent') {
      const { model, contents, config } = payload;
      const result = await executeWithRetry(async (ai) => {
          const response = await ai.models.generateContent({ model, contents, config });
          return { 
              text: response.text,
              groundingMetadata: response.candidates?.[0]?.groundingMetadata // Return sources for URL extraction
          };
      });
      return res.status(200).json(result);
    }

    if (action === 'generateImages') {
      const { prompt, safetySettings } = payload;

      // Waterfall Strategy: Ideogram -> Imagen -> Grok -> OpenAI -> Flash

      try {
          const ideogramB64 = await generateIdeogramImage(prompt);
          if (ideogramB64) return res.status(200).json({ base64: ideogramB64, provider: 'ideogram' });
      } catch (e) { console.warn("[Waterfall] Ideogram skipped:", e.message); }

      try {
          const geminiResult = await executeWithRetry(async (ai) => {
              console.log("[Waterfall] Attempting Imagen 3...");
              const response = await ai.models.generateImages({
                  model: 'imagen-3.0-generate-002',
                  prompt: prompt.replace(/8k/gi, ''), // Double ensure clean prompt
                  config: { numberOfImages: 1, aspectRatio: "1:1", safetySettings }
              });
              const bytes = response.generatedImages?.[0]?.image?.imageBytes;
              if (!bytes) throw new Error("No bytes from Imagen");
              return { base64: bytes, provider: 'imagen-3' };
          });
          return res.status(200).json(geminiResult);
      } catch (geminiError) {
          console.warn("[Waterfall] Imagen 3 failed:", geminiError.message);

          // Flash Fallback
          try {
              const flashResult = await executeWithRetry(async (ai) => {
                  console.log("[Waterfall] Fallback to Gemini Flash Image...");
                  const response = await ai.models.generateContent({
                      model: 'gemini-2.5-flash-image',
                      contents: { parts: [{ text: prompt }] }
                  });
                  const bytes = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
                  if (!bytes) throw new Error("No data from Flash Image");
                  return { base64: bytes, provider: 'gemini-flash' };
              });
              return res.status(200).json(flashResult);
          } catch (flashError) {
              console.warn("[Waterfall] Gemini Flash failed:", flashError.message);
          }
      }

      try {
          const grokB64 = await generateGrokImage(prompt);
          if (grokB64) return res.status(200).json({ base64: grokB64, provider: 'grok' });
      } catch (e) { console.warn("[Waterfall] Grok failed:", e.message); }

      try {
          const openAIB64 = await generateOpenAIImage(prompt);
          if (openAIB64) return res.status(200).json({ base64: openAIB64, provider: 'openai' });
      } catch (e) { console.warn("[Waterfall] OpenAI failed:", e.message); }

      return res.status(500).json({ error: "All image providers failed." });
    }

    if (action === 'generateVideos') {
       const { model, prompt, config } = payload;
       const result = await executeWithRetry(async (ai, currentKey) => {
           let operation = await ai.models.generateVideos({ model, prompt, config });
           let attempts = 0;
           while (!operation.done && attempts < 20) { 
               await delay(3000);
               operation = await ai.operations.getVideosOperation({ operation: operation });
               attempts++;
           }
           if (!operation.done) throw new Error("Video timeout");
           const uri = operation.response?.generatedVideos?.[0]?.video?.uri;
           if (!uri) throw new Error("No URI");

           const vidRes = await fetch(`${uri}&key=${currentKey}`);
           if (!vidRes.ok) throw new Error("Video download failed");
           const buf = await vidRes.arrayBuffer();
           return { videoBase64: Buffer.from(buf).toString('base64') };
       });
       return res.status(200).json(result);
    }

    return res.status(400).json({ error: `Unknown action: ${action}` });

  } catch (error) {
    console.error('[API Error]:', error);
    return res.status(500).json({ error: error.message || 'Server Error' });
  }
};

import { TrendingTopic, OpportunityPost } from '../../types';
import { callBackend, getSystemCache, setSystemCache, shuffleArray, cleanJsonText, decodeHtml, Type } from './core';

// Helper to check if news image is valid (no pixels, ads, etc)
const isValidNewsImage = (url: string): boolean => {
    if (!url) return false;
    const lower = url.toLowerCase();
    const badKeywords = ['pixel', 'tracker', 'analytics', 'facebook.com/tr', 'ads', 'doubleclick', 'button', 'share_icon', 'logo', 'placeholder'];
    if (badKeywords.some(k => lower.includes(k))) return false;
    return true;
};

const extractImageUrlFromItem = (item: Element): string => {
    let imageUrl = '';
    const mediaContent = item.getElementsByTagName('media:content')[0];
    if (mediaContent) imageUrl = mediaContent.getAttribute('url') || '';
    if (!imageUrl) {
        const enclosure = item.getElementsByTagName('enclosure')[0];
        if (enclosure && (enclosure.getAttribute('type') || '').startsWith('image')) imageUrl = enclosure.getAttribute('url') || '';
    }
    if (!imageUrl) {
        const descRaw = item.querySelector("description")?.textContent || "";
        const match = decodeHtml(descRaw).match(/<img[^>]+src=["']([^"']+)["']/i);
        if (match && match[1] && isValidNewsImage(match[1])) imageUrl = match[1];
    }
    if (imageUrl && (imageUrl.includes('googleusercontent.com') || imageUrl.includes('ggpht.com'))) {
        imageUrl = imageUrl.replace(/=[wh]\d+[-a-z0-9]*/, '=w800') + (imageUrl.match(/=[wh]\d+/) ? '' : '=w800');
    }
    return imageUrl;
};

const fetchRssContent = async (targetUrl: string): Promise<string> => {
    const data = await callBackend('fetchRss', { url: targetUrl });
    if (!data.text) throw new Error("Backend returned empty RSS content");
    return data.text;
};

const fetchRealtimeRss = async (keyword: string): Promise<TrendingTopic[]> => {
    // Fix: Force 'Taiwan' in query to prevent IP-based localization (US Server -> HK/Global Chinese results)
    const queryTerm = keyword.includes('台灣') || keyword.includes('Taiwan') ? keyword : `${keyword} 台灣`;

    // Construct Google News URL with explicit Taiwan bias
    const rssUrl = `https://news.google.com/rss/search?q=${encodeURIComponent(queryTerm)}+when:2d&hl=zh-TW&gl=TW&ceid=TW:zh-Hant`;

    try {
        const xmlString = await fetchRssContent(rssUrl);
        const parser = new DOMParser();
        const xml = parser.parseFromString(xmlString, "text/xml");
        const items = xml.querySelectorAll("item");
        const results: TrendingTopic[] = [];

        for (let i = 0; i < Math.min(items.length, 20); i++) {
            const item = items[i];
            const title = item.querySelector("title")?.textContent || "";
            const link = item.querySelector("link")?.textContent || "";
            const imageUrl = extractImageUrlFromItem(item);
            if (title && link) results.push({ title, description: title, url: link, imageUrl });
        }
        return results;
